// ── PHARMACOLOGY CARDS ─────────────────────────────────────────────────────
const PHARMA_CARDS = [
// ── BASICS ──────────────────────────────────────────────────────────────────
{id:"b1",cat:"Basics",title:"Pharmaceutic, Pharmacokinetic & Pharmacodynamic Phases",subtitle:"Define the 3 pharmacology phases",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"Three phases: (1) Pharmaceutic – drug dissolves from solid pill form into liquid. (2) Pharmacokinetic – ADME: Absorption, Distribution, Metabolism, Excretion. (3) Pharmacodynamic – movement of drug into a cell & potential of drug to bind to cellular receptors.",uses:["Understanding how drugs work in the body"],sideEffects:[],patientEd:[],nursing:[],mnemonic:"ADME – Absorption, Distribution, Metabolism, Excretion"},
{id:"b2",cat:"Basics",title:"Pharmacokinetics",subtitle:"Define pharmacokinetics; describe the 4 steps (ADME)",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"The study of how drugs are moved throughout the body. ADME: Absorption (location of admin → bloodstream), Distribution (transported by bodily fluids to target site), Metabolism (breakdown of medication), Excretion (removal of unmetabolized drug from body).",uses:["Understand drug movement in the body"],sideEffects:[],patientEd:[],nursing:["Factors affecting absorption: route, blood perfusion, drug form","Factors affecting distribution: plasma protein binding, circulation","Factors affecting metabolism: age (infants & elderly), first-pass effect","Factors affecting excretion: kidney dysfunction → ↑ duration & intensity of drug"],mnemonic:"ADME mnemonic: A Dude Makes Excuses"},
{id:"b3",cat:"Basics",title:"First Pass Effect",subtitle:"Define first pass effect; how to avoid it",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"When a drug is taken orally it is metabolized by the liver or gut BEFORE reaching systemic circulation. The drug's concentration is reduced and only part of the dose reaches the bloodstream.",uses:["Explains why oral doses must be higher than IV doses"],sideEffects:[],patientEd:["Some medications bypass first pass when given SubQ, IM, or IV"],nursing:["First pass effect reduces oral bioavailability","Routes that avoid first pass: IV (100% bioavailability), IM, SubQ, sublingual, transdermal"],mnemonic:""},
{id:"b4",cat:"Basics",title:"Pharmacodynamics",subtitle:"Define pharmacodynamics; know key terms",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"Movement of the drug into a cell and potential of the drug to bind to cellular receptors. Includes agonist/antagonist interactions, drug receptor binding, loading dose concepts.",uses:["Understanding drug-body interaction"],sideEffects:[],patientEd:[],nursing:[],mnemonic:"AGONIST = helps WITH the body; ANTAGONIST = works AGAINST; LOADING DOSE = reaches therapeutic levels faster; CONTRAINDICATION = reason to AVOID; ADVERSE REACTION = harmful/opposite reaction; THERAPEUTIC EFFECT = desired response"},
{id:"b5",cat:"Basics",title:"Half-Life",subtitle:"Define half-life; short vs. long half-life examples",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"The time it takes for the drug concentration in the body to be reduced by half (50%). Determines dosing frequency.",uses:["Predicting drug dosing intervals","Understanding drug accumulation"],sideEffects:[],patientEd:[],nursing:["Short half-life: acts quickly, higher dependency risk, lower toxicity risk (e.g., oxycodone, rapid-acting insulin)","Long half-life: lasts longer, higher toxicity risk, lower dependency risk (e.g., fluoxetine, chloroquine)"],mnemonic:"Short half-life = Short acting. Long half-life = Long lasting."},
{id:"b6",cat:"Basics",title:"Therapeutic Index (TI)",subtitle:"Define TI; common therapeutic levels; narrow vs. wide TI",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"The level of medication needed to produce the desired effect without toxicity. LOW/NARROW TI = small margin between effective dose and toxic dose → requires close monitoring.",uses:["Monitoring drug safety"],sideEffects:[],patientEd:["Report any unusual symptoms immediately when on narrow TI drugs"],nursing:["Narrow TI drugs: Digoxin (0.5–2 ng/mL), Lithium (0.6–1.2 mEq/L), Theophylline (10–20 mcg/mL), Phenytoin (10–20 mcg/mL), Vancomycin (peak 25–40; trough 5–15 mcg/mL)","Wide TI drugs require less monitoring"],mnemonic:"Narrow TI drugs: 'DIG' – Digoxin, I-lithium (Li), Got Theophylline"},
{id:"b7",cat:"Basics",title:"Allergic Reaction",subtitle:"Define; signs & symptoms; steps for care; cross sensitivity",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"Immune response to a drug. Mild: rash, urticaria, pruritus, fever. Severe (anaphylaxis): wheezing, hypotension, loss of airway, anaphylactic shock.",uses:["Recognizing and treating drug allergies"],sideEffects:[],patientEd:["Carry epinephrine (EpiPen) if known severe allergy","Always report all allergies before receiving any medication"],nursing:["STEPS: Stop administration → Epinephrine + antihistamines → ABCs → IM Epi first, then Benadryl → Document → Corticosteroids","CROSS-SENSITIVITY: allergy to penicillin → possible allergy to cephalosporins"],mnemonic:""},
{id:"b8",cat:"Basics",title:"Drug Schedules",subtitle:"Describe schedules I–V; risk for abuse; prescription requirements",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"DEA classification of controlled substances by abuse potential. Schedule I: highest abuse, no accepted medical use. Schedule V: lowest abuse potential.",uses:["Prescribing and dispensing controlled substances"],sideEffects:[],patientEd:[],nursing:["Schedule I: heroin, LSD, marijuana (research only)","Schedule II: morphine, oxycodone, fentanyl, cocaine – HIGH abuse, no refills","Schedule III: testosterone, ketamine, some steroids – moderate abuse","Schedule IV: benzodiazepines (Xanax, Valium, Ativan), tramadol – low abuse","Schedule V: cough syrups with small amounts of codeine, Lyrica – lowest abuse"],mnemonic:""},
{id:"b9",cat:"Basics",title:"Drug Names",subtitle:"Chemical name vs. generic name vs. trade/brand name",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"Three levels of drug naming. Chemical: describes molecular structure (rarely used clinically). Generic: official nonproprietary name (always lowercase). Trade/Brand: proprietary name given by manufacturer (capitalized).",uses:["Drug identification and safety"],sideEffects:[],patientEd:["Generic and brand name drugs contain the same active ingredient","Generics are usually less expensive"],nursing:["Always use generic names in documentation when possible","Trade names vary by country and manufacturer"],mnemonic:"Chemical = Science name. Generic = Official name. Brand = Company name. Ex: ibuprofen → Advil/Motrin"},
{id:"b10",cat:"Basics",title:"Rights of Medication Administration",subtitle:"The 10 rights; how to verify each; common medication errors",generics:[],trades:[],drugClass:"Pharmacology Concept",suffix:"",mechanism:"Framework to prevent medication errors: Right Patient, Right Medication, Right Dose, Right Time, Right Route, Right Documentation, Right Education, Right to Refuse, Right Reason, Right Response.",uses:["Preventing medication errors"],sideEffects:[],patientEd:["You have the right to refuse any medication","Always know what medication you are taking and why"],nursing:["Use 2 patient identifiers before giving ANY medication","Verify all 10 rights before administration","Document immediately after giving medication, not before"],mnemonic:"10 rights: Patient, Med, Dose, Time, Route, Documentation, Education, Refuse, Reason, Response"},
// ── RESPIRATORY ─────────────────────────────────────────────────────────────
{id:"r1",cat:"Respiratory",title:"Short-Acting Beta2-Agonists (SABAs)",subtitle:"Rescue inhaler for acute asthma attacks",generics:["albuterol","levalbuterol","terbutaline"],trades:["Proventil HFA","Ventolin HFA","Xopenex"],drugClass:"Bronchodilator",suffix:"Suffix: -TEROL | Prefix: TER-",mechanism:"Stimulates beta-2 receptors in the sympathetic nervous system → relaxes smooth muscle in bronchioles → bronchodilation. Think: 'alBUTEROL opens airways FAST.'",uses:["Acute asthma attacks (rescue inhaler)","Bronchospasms","Asthma exacerbations"],sideEffects:["Tachycardia (HR > 100 bpm)","Tremors / feeling 'jittery'","Palpitations","Cardiac arrhythmia","Insomnia / anxiety","Thrush (oral/esophageal candidiasis)"],patientEd:["Shake well before each use","2–4 puffs every 20 minutes (max 3 doses)","Rinse mouth with water after each use to prevent thrush","Use spacer device for better delivery"],nursing:["If 3 doses of 2–4 puffs are not effective → notify HCP & apply O2","Unlike LABAs, SABAs are for ACUTE (not maintenance) use","Monitor HR and BP during acute use"],mnemonic:"SABA = Short-Acting = STAT relief. Think: A-B-C-D = Albuterol Bronchodilates Completely DONE fast"},
{id:"r2",cat:"Respiratory",title:"Long-Acting Beta2-Agonists (LABAs)",subtitle:"Long-term bronchospasm prevention; NOT for rescue",generics:["salmeterol","formoterol","budesonide/formoterol","olodaterol"],trades:["Serevent Diskus","Foradil","Symbicort","Striverdi Respimat"],drugClass:"Bronchodilator",suffix:"Suffix: -TEROL",mechanism:"Activates beta-2 adrenergic receptors in the lung → relaxes smooth muscle in bronchioles. Works slowly and steadily for LONG-TERM control. NOT for acute attacks.",uses:["Chronic bronchitis","Long-term COPD management","Prevention of bronchospasms"],sideEffects:["Tachycardia (HR > 100 bpm)","Tremors / 'jittery' feeling","Palpitations","Cardiac arrhythmia","Thrush (oral/esophageal candidiasis)"],patientEd:["ALWAYS take bronchodilator BEFORE corticosteroid: (1) Bronchodilator opens airway, (2) wait 5 min, (3) then corticosteroid","Rinse mouth after use to prevent thrush","NOT a rescue inhaler — do NOT use during acute attack"],nursing:["Never use as rescue therapy","Often combined with inhaled corticosteroids (ICS) for asthma","Prevent thrush: rinse mouth with water after each use"],mnemonic:"LABA = Long-Acting = Long-Term. Think: SalMETEROL = Slow & Steady"},
{id:"r3",cat:"Respiratory",title:"Corticosteroids (Inhaled/Systemic)",subtitle:"Anti-inflammatory; suppress immune response",generics:["prednisone","prednisolone","dexamethasone","hydrocortisone","budesonide","beclomethasone","fluticasone","flunisolide"],trades:["Deltasone","Decadron","Cortef","Pulmicort","QVAR","Flovent HFA","Aerobid"],drugClass:"Corticosteroid (glucocorticoid)",suffix:"Suffix: -SONE, -IDE",mechanism:"Suppresses the immune system by inhibiting prostaglandin and arachidonic acid synthesis → prevents inflammatory cascade → reduces airway inflammation and edema.",uses:["Asthma (maintenance)","COPD exacerbations","Inflammatory bowel disease (IBD)","Rheumatoid arthritis","Pneumonia/respiratory infections"],sideEffects:["Sugar ↑ – hyperglycemia","Immune suppression (↑ infection risk)","Adrenal gland suppression (with long-term use)","Delayed wound healing","Hypertension","Mental status changes (mood swings, psychosis)","Osteoporosis (long-term use)","Thrush (inhaled steroids)"],patientEd:["REPORT signs of infection (fever, chills)","Never stop abruptly — must be TAPERED","Annual eye exam (risk of cataracts/glaucoma)","↓ sodium diet; ↑ calcium + Vitamin D"],nursing:["Taper the dose when discontinuing — do NOT stop abruptly (adrenal crisis risk)","Inhaled: rinse mouth after each use (prevents thrush)","Monitor blood glucose in diabetic patients","Monitor for signs of adrenal suppression"],mnemonic:"SIADH: Sugar↑, Immune↓, ADrenal suppression, Delayed wound healing, HTN, mental status changes"},
{id:"r4",cat:"Respiratory",title:"Acetylcysteine (Acetadote)",subtitle:"Mucolytic; also antidote for acetaminophen toxicity",generics:["acetylcysteine"],trades:["Mucomyst","Acetadote"],drugClass:"Mucolytic",suffix:"",mechanism:"Breaks apart and dissolves thick mucus in the airway → eases gas exchange. Also replenishes glutathione in the liver → used as antidote for acetaminophen overdose.",uses:["COPD","Cystic fibrosis","Tracheostomy patients","Acetaminophen (Tylenol) toxicity antidote"],sideEffects:["Chest tightness","Worsening of bronchospasms","Stomatitis (mouth sores)","Unpleasant taste/odor (rotten egg smell)","Nausea/vomiting"],patientEd:["Adequate fluid intake (helps thin secretions)","Report worsening of breathing"],nursing:["Assess history of asthma (can aggravate bronchospasm)","For acetaminophen toxicity: check serum acetaminophen level, LFTs","Administer within 8–10 hours of acetaminophen overdose for best results"],mnemonic:"Acetylcysteine = A-CYST = Antidote for Cyst(eine depletion in liver)"},
{id:"r5",cat:"Sick Call",title:"Guaifenesin (Mucinex)",subtitle:"Expectorant; thins mucus so patient can cough it up",generics:["guaifenesin"],trades:["Mucinex","Robitussin AC"],drugClass:"Expectorant",suffix:"",mechanism:"Increases and thins respiratory secretions → makes it easier to cough up mucus (expectorate). Think: 'Guaifenesin = Get it OUT.'",uses:["Acute bronchitis","Asthma","Pulmonary emphysema","Cystic fibrosis","Rhinitis","Common cold"],sideEffects:["Nausea","Headache","Rash","Dizziness"],patientEd:["Take with a full glass of water (8 oz)","Drink 2 liters of fluid/day to help thin mucus","Do NOT use alcohol","Report fever > 100.4°F (38°C)"],nursing:["Not effective without adequate fluid intake","Available OTC","Monitor for productive cough effectiveness"],mnemonic:"Guaifenesin = G = 'Get the Gunk Out'"},
{id:"r6",cat:"Respiratory",title:"Inhaled Anticholinergics (LAMAs)",subtitle:"COPD maintenance; blocks parasympathetic bronchospasm",generics:["ipratropium","tiotropium"],trades:["Atrovent","Spiriva","HandiHaler"],drugClass:"Anticholinergic (LAMA – Long-Acting Muscarinic Antagonist)",suffix:"Suffix: -TROPIUM",mechanism:"Blocks muscarinic (parasympathetic) receptors in the bronchi → prevents bronchoconstriction → relaxes smooth muscle → bronchodilation. Parasympathetic normally constricts airways; blocking it opens them.",uses:["COPD (maintenance)","Allergy/exercise-induced asthma","Rhinitis","Bronchospasms"],sideEffects:["CAN'T SEE – blurred vision, dry eyes","CAN'T PEE – urinary retention","CAN'T SPIT – dry mouth, ↓ sweat","CAN'T POOP – constipation","Cognitive dysfunction & dizziness"],patientEd:["For dry mouth: suck on sugar-free candy","For constipation: stool softeners, fiber, fluids","Fluids help with bowel movements","Fruits, Fiber & Fluids"],nursing:["Often combined with beta-2 agonists in nebulizer","Spiriva capsules MUST be inserted into specialized HandiHaler device — NEVER swallow or inject","Available as nasal aerosol for rhinitis","Monitor for urinary retention"],mnemonic:"CANT: Can't See, Can't Pee, Can't Spit, Can't Poop"},
{id:"r7",cat:"Respiratory",title:"Leukotriene Inhibitors",subtitle:"Prevent bronchospasm; treat allergic asthma",generics:["montelukast","zafirlukast"],trades:["Singulair","Accolate"],drugClass:"Leukotriene inhibitor (receptor antagonist)",suffix:"Suffix: -LUKAST",mechanism:"Inhibits leukotriene receptors → blocks inflammatory mediators → prevents bronchoconstriction and mucus secretion in airways. Anti-inflammatory and bronchodilatory effect.",uses:["Seasonal/allergic asthma","Allergic rhinitis","Exercise-induced bronchospasm"],sideEffects:["Flu-like symptoms (headache, fatigue)","Elevated liver enzymes","Mood changes / suicidal ideation (BLACK BOX WARNING)"],patientEd:["Takes 1–2 weeks to become effective","Take 2 hours BEFORE exercise if used for exercise-induced asthma","NEVER use as a rescue inhaler","Report mood changes, depression, or suicidal thoughts immediately"],nursing:["MONITOR: LFTs (liver function tests)","Monitor for suicidal ideation (black box warning)","Not for acute bronchospasm"],mnemonic:"montelukast = MONTE-lukast = MONitor for mood changes"},
{id:"r8",cat:"Respiratory",title:"Theophylline (Theobid)",subtitle:"Narrow TI bronchodilator; monitor blood levels closely",generics:["theophylline"],trades:["Theo-24","Theobid"],drugClass:"Bronchodilator (methylxanthine)",suffix:"",mechanism:"Inhibits phosphodiesterase enzyme → increases cAMP → relaxes bronchial smooth muscle → bronchodilation. Also mild anti-inflammatory effect. NARROW THERAPEUTIC INDEX.",uses:["Asthma (no longer first-line)","COPD","Chronic bronchitis","Emphysema","Apnea of prematurity"],sideEffects:["TOXICITY signs: nausea/vomiting, tachycardia, headache, restlessness, nervousness, arrhythmias, SEIZURES"],patientEd:["Avoid caffeine (↑ theophylline toxicity)","Smoking ↓ theophylline levels (needs higher dose)","Report nausea, heart racing, or seizures immediately"],nursing:["Therapeutic range: 10–20 mcg/mL","< 10 = subtherapeutic; > 20 = TOXIC","Monitor HR, ECG, serum theophylline levels","Narrow TI — monitor closely"],mnemonic:"Theophylline TI = 10–20 mcg/mL. TOXIC > 20!"},
{id:"r9",cat:"Respiratory",title:"Antihistamines (H1 Blockers)",subtitle:"1st gen (sedating) vs. 2nd gen (non-sedating)",generics:["diphenhydramine","chlorpheniramine","hydroxyzine","promethazine","loratadine","fexofenadine","cetirizine","desloratadine"],trades:["Benadryl","Chlor-Trimeton","Vistaril","Phenergan","Claritin","Allegra","Zyrtec","Clarinex"],drugClass:"Histamine antagonist (H1 blocker)",suffix:"1st gen: -RAMINE | 2nd gen: -ADINE",mechanism:"Block H1 histamine receptors (created by CNS) → prevent histamine-mediated allergic response. 1st generation crosses blood-brain barrier → sedating. 2nd generation does not cross BBB → non-sedating.",uses:["Allergic rhinitis","Seasonal allergies","Common cold symptoms","Allergic reaction/urticaria","Motion sickness (1st gen only)"],sideEffects:["CAN'T SEE – blurred vision, dry eyes","CAN'T PEE – urinary retention","CAN'T SPIT – dry mouth, ↓ sweating","CAN'T POOP – constipation","Sedation/drowsiness (especially 1st gen)","FALL RISK (1st gen)"],patientEd:["Available OTC for most","1st gen causes sedation — avoid driving/alcohol","2nd gen (Claritin, Zyrtec, Allegra) are less sedating","Can be taken with epinephrine for severe allergic reactions"],nursing:["1st gen = FALL RISK due to sedation","Diphenhydramine (Benadryl) used adjunctively for anaphylaxis (with epinephrine)","Do NOT use in elderly — high fall/anticholinergic risk"],mnemonic:"CANT (same as anticholinergics): Can't See, Pee, Spit, Poop"},
{id:"r10",cat:"Respiratory",title:"Epinephrine for Anaphylaxis",subtitle:"First-line treatment for anaphylactic shock",generics:["epinephrine"],trades:["EpiPen","Auvi-Q","Adrenaclick"],drugClass:"Beta-adrenergic agonist (sympathomimetic)",suffix:"",mechanism:"Causes bronchodilation (beta-2), vasoconstriction (alpha-1), and increases HR/BP (beta-1) → rapidly reverses anaphylactic shock. Activates the fight-or-flight response to counteract massive histamine release.",uses:["Anaphylactic shock (first-line)","Cardiac arrest","Severe allergic reactions"],sideEffects:["Hypertension","Tachycardia/palpitations","Tremors","Headache","Anxiety"],patientEd:["Carry EpiPen at ALL times if prescribed","Inject into outer thigh (can go through clothing if needed)","After using EpiPen: go to ER IMMEDIATELY — effect wears off in 15–20 min","Keep 2 EpiPens available at all times"],nursing:["ALWAYS document every use of epinephrine","Monitor cardiac rhythm after administration","IM injection into outer thigh preferred over SubQ for faster absorption","Have second EpiPen ready — may need repeat dose in 5–15 min"],mnemonic:"Epi = Emergency! First-line for anaphylaxis"},
// ── IMMUNE SYSTEM ────────────────────────────────────────────────────────────
{id:"i1",cat:"Immune",title:"Antibiotic Classes Overview",subtitle:"Suffix/prefix patterns; major antibiotic classes",generics:[],trades:[],drugClass:"Antibiotic Overview",suffix:"Tetracyclines: -CYCLINE | Cephalosporins: CEF-, CEPH- | Sulfonamides: SULFA- | Aminoglycosides: -MYCIN/-MICIN | Fluoroquinolones: -FLOXACIN | Penicillins: -CILLIN | Antivirals: -VIR",mechanism:"Antibiotics work via different mechanisms: beta-lactam ring destroys cell wall (penicillin, cephalosporins, vancomycin), inhibit protein synthesis (aminoglycosides, tetracyclines, macrolides), inhibit DNA replication (fluoroquinolones), inhibit folic acid synthesis (sulfonamides).",uses:["Bacterial infections (various)"],sideEffects:[],patientEd:["Always finish the entire course even if feeling better"],nursing:["ALWAYS obtain culture & sensitivity BEFORE starting antibiotic","Know bacteriostatic vs. bactericidal distinction"],mnemonic:"Saved by the Suffixes: -CYCLINE, CEF-/CEPH-, SULFA-, -MYCIN/-MICIN, -FLOXACIN, -CILLIN, -VIR"},
{id:"i2",cat:"Immune",title:"Bacteriostatic vs. Bactericidal",subtitle:"Key difference: SLOWS growth vs. KILLS bacteria",generics:[],trades:[],drugClass:"Antibiotic Concept",suffix:"",mechanism:"BACTERIOSTATIC: SLOWS or prevents bacterial growth without directly killing them. Relies on immune system to finish the job. Examples: tetracyclines, macrolides, sulfonamides, clindamycin, trimethoprim. BACTERICIDAL: KILLS bacteria directly. Examples: penicillins, cephalosporins, fluoroquinolones, aminoglycosides, vancomycin.",uses:["Choosing appropriate antibiotic therapy"],sideEffects:[],patientEd:[],nursing:["Use bactericidal in immunocompromised patients (immune system can't finish the job)","Bacteriostatic drugs work best when immune system is intact"],mnemonic:"STATIC = Stops growth. CIDAL = Kills dead. 'I'm suicidal' = kills bacteria dead"},
{id:"i3",cat:"Immune",title:"Culture & Sensitivity Test",subtitle:"Always obtain BEFORE starting antibiotics",generics:[],trades:[],drugClass:"Diagnostic Concept",suffix:"",mechanism:"CULTURE: identifies what organism is causing the infection. SENSITIVITY: identifies which antibiotic will effectively treat the infection. Together guides appropriate antibiotic selection.",uses:["Guiding antibiotic therapy","Identifying causative organism"],sideEffects:[],patientEd:["The nurse collects a sample before giving any antibiotics"],nursing:["ALWAYS obtain culture & sensitivity BEFORE giving first antibiotic dose","Positive culture = organism growth present","Negative culture = no organism growth","Sensitivity shows which antibiotics have zones of inhibition (effective) vs. no zone (resistant)"],mnemonic:"C&S BEFORE antibiotics — Culture = What bug? Sensitivity = What drug kills it?"},
{id:"i4",cat:"Immune",title:"Superinfection",subtitle:"New infection during antibiotic treatment; C. diff risk",generics:[],trades:[],drugClass:"Infectious Disease Concept",suffix:"",mechanism:"A new infection that develops DURING treatment of a primary infection. Antibiotics kill normal flora in GI tract → opportunistic organisms (like C. difficile, Candida) overgrow → superinfection.",uses:["Awareness during antibiotic therapy"],sideEffects:[],patientEd:["Take probiotics while on antibiotics to restore good gut bacteria","Report diarrhea (especially if severe or bloody)"],nursing:["C. diff hallmark: foul-smelling, watery diarrhea (3+ per day)","Prevention: use antibiotics only when confirmed bacterial infection","Treat C. diff with metronidazole (Flagyl) or vancomycin (oral)","Contact precautions for C. diff patients"],mnemonic:"Super-infection = Super-opportunist overgrowth when normal flora wiped out"},
{id:"i5",cat:"Immune",title:"Vancomycin (Vancocin)",subtitle:"Last-resort antibiotic for MRSA and C. diff",generics:["vancomycin"],trades:["Vancocin"],drugClass:"Glycopeptide antibiotic",suffix:"",mechanism:"BACTERICIDAL. Inhibits bacterial cell wall synthesis by binding to D-Ala-D-Ala terminus → prevents cross-linking of cell wall → bacteria lyse and die. Effective against gram-positive organisms.",uses:["MRSA (methicillin-resistant Staphylococcus aureus)","C. difficile infections (oral form)","Serious gram-positive infections"],sideEffects:["Red Man Syndrome: flushing/redness of head, neck, upper body during infusion (NOT a true allergy — caused by too-fast infusion)","Nephrotoxic (kidney damage)","Ototoxic (hearing loss, tinnitus)","Thrombophlebitis at IV site"],patientEd:["Report redness, flushing, or itching during infusion","Report ringing in ears or changes in hearing","Report decreased urination"],nursing:["INFUSE OVER AT LEAST 60 MINUTES to prevent Red Man Syndrome (not allergy — rate-related)","Therapeutic levels: Peak 25–40 mcg/mL, Trough 5–15 mcg/mL","Monitor: BUN, creatinine (nephrotoxic), hearing","↑ Fluids during treatment"],mnemonic:"Van-co-mycin = Van comes to KILL MRSA. Peak 25-40 / Trough 5-15"},
{id:"i6",cat:"Immune",title:"Cephalosporins",subtitle:"Beta-lactam antibiotics; CEF-/CEPH- prefix; cross-allergy with penicillin",generics:["cefazolin","ceftriaxone","cefuroxime","cephalexin","cefdinir","cefpodoxime"],trades:["Kefzol","Rocephin","Ceftin","Keflex","Omnicef","Vantin"],drugClass:"Beta-lactam antibiotic",suffix:"Prefix: CEF-, CEPH-",mechanism:"BACTERICIDAL. Beta-lactam antibiotic that destroys the bacterial cell wall by inhibiting peptidoglycan cross-linking → bacteria cannot maintain structural integrity → cell lysis and death.",uses:["Respiratory infections","UTIs","Skin/soft tissue infections","Prophylaxis for surgery","Otitis media","Strep throat","Meningitis"],sideEffects:["Nausea, vomiting, diarrhea","Nephrotoxicity","Stevens-Johnson Syndrome (SJS) — rare but life-threatening rash","Cross-sensitivity with penicillin"],patientEd:["STOP medication if rash, skin lesions, or fever occur (may be SJS)","Do NOT drink alcohol while on cephalosporins","Cephalosporins make oral contraceptives ineffective — use backup contraception","Finish the ENTIRE course"],nursing:["Ask about penicillin allergy BEFORE administering (cross-sensitivity in ~1-2% of patients)","Monitor renal function (nephrotoxic)","Finish entire antibiotic course","Watch for SJS symptoms"],mnemonic:"CEF = Cell wall Elimination Fighters. Cross-allergy with PCN!"},
{id:"i7",cat:"Immune",title:"Sulfonamides (Sulfa Drugs)",subtitle:"Bacteriostatic; photosensitivity; Stevens-Johnson risk",generics:["sulfamethoxazole/trimethoprim","sulfasalazine"],trades:["Bactrim (SMX/TMP)","Azulfidine"],drugClass:"Sulfonamide antibiotic",suffix:"Prefix: SULFA-",mechanism:"BACTERIOSTATIC. Inhibits dihydropteroate synthase → blocks folic acid synthesis (bacteria must make their own folic acid, humans get it from diet) → slows bacterial multiplication.",uses:["UTIs (especially E. coli)","Ulcerative colitis (sulfasalazine)","Acute otitis media","Topical: burn wound infections","Pneumocystis jiroveci pneumonia (PCP) in immunocompromised"],sideEffects:["5 S's of SULFAS: Sun (photosensitivity), Sour Stomach (nausea/vomiting/diarrhea), Stevens-Johnson Syndrome, Stones (crystalluria/kidney stones), Severe hypersensitivity"],patientEd:["Wear sunscreen and protective clothing","Report rash, fever, or blistering (SJS)","Drink plenty of water (↓ kidney stone risk)","Finish entire course of antibiotics"],nursing:["Assess for sulfa allergies (cross-sensitivity with thiazide diuretics, furosemide, sulfonylureas)","Monitor CBC for blood dyscrasias","↑ fluid intake to prevent crystalluria","Monitor LFTs and renal function"],mnemonic:"5 S's: Sun, Sour Stomach, SJS, Stones, Severe allergy"},
{id:"i8",cat:"Immune",title:"Fluoroquinolones",subtitle:"Bactericidal; DNA inhibitor; tendon rupture risk",generics:["ciprofloxacin","levofloxacin","moxifloxacin"],trades:["Cipro","Levaquin","Avelox"],drugClass:"Fluoroquinolone antibiotic",suffix:"Suffix: -FLOXACIN",mechanism:"BACTERICIDAL. Inhibits DNA gyrase (topoisomerase II & IV) → prevents bacterial DNA from uncoiling/replicating → stops bacterial reproduction.",uses:["UTIs","Sexually transmitted infections (STIs)","Respiratory infections","Bone/joint infections","Anthrax prophylaxis"],sideEffects:["Photosensitivity","QT prolongation (risk for torsades de pointes — life-threatening arrhythmia)","TENDON RUPTURE (especially Achilles tendon) — BLACK BOX WARNING","Peripheral neuropathy","Crystalluria/kidney stones"],patientEd:["Wear sunscreen; avoid direct sun exposure","Report tendon pain IMMEDIATELY — stop activity and contact HCP","Avoid calcium-containing foods/antacids within 2 hrs (↓ absorption)","Stay well-hydrated"],nursing:["QT prolongation — monitor ECG","BLACK BOX WARNING: tendon rupture risk (especially in >60, on steroids, or with kidney/heart/lung transplant)","Avoid in children and pregnant women (affects cartilage development)","Monitor renal function"],mnemonic:"FLOXacin = FLOX tendons (tendon rupture!) + QT prolongation"},
{id:"i9",cat:"Immune",title:"Penicillin",subtitle:"Bactericidal; destroys cell wall; allergy risk",generics:["penicillin G","penicillin V","amoxicillin","ampicillin","amoxicillin-clavulanate"],trades:["Bicillin","Amoxil","Principen","Augmentin"],drugClass:"Beta-lactam antibiotic (penicillin)",suffix:"Suffix: -CILLIN",mechanism:"BACTERICIDAL. Destroys bacterial cell wall by binding to penicillin-binding proteins → inhibits peptidoglycan synthesis → bacterial cell lysis and death.",uses:["UTIs","Strep throat/meningitis","STIs (syphilis, gonorrhea)","Respiratory infections/pneumonia","Otitis media","Skin infections"],sideEffects:["GI upset (nausea, vomiting, diarrhea)","Anaphylaxis (most dangerous)","Rash/urticaria (hives)","Wheezing/bronchospasm","Hypotension"],patientEd:["Take with food to reduce GI upset","Penicillin makes oral contraceptives less effective — use backup contraception","Finish the ENTIRE antibiotic course","Report rash, hives, or difficulty breathing IMMEDIATELY"],nursing:["Ask about penicillin allergy BEFORE first dose","Cross-sensitivity with cephalosporins — ask about both","Finish entire course of therapy","Have epinephrine available for anaphylaxis"],mnemonic:"PCN = Penicillin Creates Nowhere for bacteria to live (destroys wall). PCN allergy → CEF cross-sensitivity"},
{id:"i10",cat:"Immune",title:"Antivirals",subtitle:"Treat viral infections; -VIR suffix; NOT antibiotics",generics:["acyclovir","valacyclovir","oseltamivir","ribavirin"],trades:["Zovirax","Valtrex","Tamiflu"],drugClass:"Antiviral",suffix:"Suffix: -VIR",mechanism:"Inhibits viral DNA/RNA replication. Acyclovir/valacyclovir: activated by viral thymidine kinase → inhibits viral DNA polymerase → prevents viral DNA synthesis. Oseltamivir: inhibits neuraminidase → prevents viral release from infected cells.",uses:["Herpes simplex (HSV-1 & 2)","Herpes zoster (shingles)","Cytomegalovirus (CMV)","Influenza (oseltamivir/Tamiflu)"],sideEffects:["GI upset (nausea, vomiting)","Headache","Nephrotoxicity (acyclovir IV)","Flu-like symptoms"],patientEd:["Start within 24–48 hours of FIRST symptoms for best effect","Does NOT cure herpes — suppresses outbreaks","Take full course; continue even if symptoms improve"],nursing:["Monitor renal function (especially IV acyclovir)","Adequate hydration to prevent nephrotoxicity","Antivirals do NOT treat bacterial infections"],mnemonic:"-VIR = Virus. Antivirals = NOT antibiotics"},
{id:"i11",cat:"Immune",title:"Tetracyclines",subtitle:"Bacteriostatic; photosensitivity; avoid in children & pregnancy",generics:["tetracycline","doxycycline","minocycline"],trades:["Sumycin","Vibramycin","Minocin"],drugClass:"Tetracycline antibiotic",suffix:"Suffix: -CYCLINE",mechanism:"BACTERIOSTATIC. Inhibits 30S ribosomal subunit → blocks protein synthesis → bacteria cannot grow or reproduce.",uses:["Acne vulgaris","Lyme disease","Rocky Mountain spotted fever","Atypical pneumonia (Mycoplasma, Chlamydia)","H. pylori (combination therapy)","STIs (chlamydia)"],sideEffects:["Photosensitivity (severe sunburn risk)","GI upset (nausea, vomiting, diarrhea)","Esophageal irritation (if not taken with adequate water)","Tooth discoloration and bone growth inhibition in children","Hepatotoxicity"],patientEd:["Wear sunscreen and protective clothing","Take 1 hour BEFORE or 2 hours AFTER meals","AVOID dairy products, antacids, iron (↓ absorption)","Finish the entire course","Do NOT take if pregnant (harms fetal bone/tooth development)"],nursing:["CONTRAINDICATED in children < 8 years (permanent tooth discoloration)","CONTRAINDICATED in pregnancy","CONTRAINDICATED in nursing mothers","Take with full glass of water and remain upright for 30 min after (prevent esophageal ulceration)"],mnemonic:"-CYCLINE = Stay out of the sunshine! No kids under 8. No pregnant women."},
{id:"i12",cat:"Immune",title:"Aminoglycosides",subtitle:"Bactericidal; NEPHROTOXIC + OTOTOXIC — monitor closely",generics:["gentamicin","tobramycin","amikacin","neomycin","streptomycin"],trades:["Garamycin","Tobrex","Amikin"],drugClass:"Aminoglycoside antibiotic",suffix:"Suffix: -MYCIN, -MICIN",mechanism:"BACTERICIDAL. Inhibits 30S ribosomal subunit → disrupts bacterial protein synthesis → causes misreading of mRNA → produces defective proteins → bacterial cell death.",uses:["Serious gram-negative infections","Bowel prep before abdominal surgery (neomycin — not absorbed)","Hepatic encephalopathy (neomycin reduces ammonia-producing gut bacteria)"],sideEffects:["NEPHROTOXIC – damages kidneys (most common)","OTOTOXIC – permanent hearing loss, tinnitus, vertigo","Neuromuscular blockade (high doses)","Blood in urine"],patientEd:["Report ringing in ears, hearing loss, dizziness IMMEDIATELY","Report decreased urine output","Drink plenty of fluids"],nursing:["Monitor: BUN (7–20 mg/dL), Creatinine (0.6–1.2 mg/dL), Urine output (≥30 mL/hr)","Monitor hearing (baseline audiogram + ongoing)","Peak/Trough levels: Peak 5–10 mcg/mL; Trough < 2 mcg/mL (gentamicin)","Give slowly; avoid concurrent nephrotoxic drugs"],mnemonic:"Amino-GLYCO-sides = GLUED to kidneys and ears. A-MEAN antibiotics (nephro + ototoxic)"},
// ── GASTROINTESTINAL ─────────────────────────────────────────────────────────
{id:"g1",cat:"Sick Call",title:"Antacids",subtitle:"Neutralize stomach acid; taken PRN for heartburn/GERD",generics:["aluminum hydroxide","calcium carbonate","magnesium hydroxide"],trades:["Tums","Rolaids","Maalox","Mylanta","Gaviscon"],drugClass:"Antacid",suffix:"",mechanism:"Neutralizes hydrochloric acid in the stomach → raises gastric pH → reduces acid irritation of esophagus and stomach lining. Antacids are BASES (alkaline).",uses:["Heartburn","GERD (acid reflux)","Peptic ulcers","Gastritis"],sideEffects:["Aluminum-based: CONSTIPATION","Magnesium-based: DIARRHEA","Alkalosis (with overuse)"],patientEd:["Take 1–2 hours AFTER meals and at bedtime","Do NOT take within 1–2 hours of other medications (interferes with absorption)","Report persistent heartburn (may need stronger therapy)"],nursing:["Antacids interfere with absorption of many drugs — check drug interactions","Avoid in patients with renal disease (risk of electrolyte imbalance)","Calcium-based antacids can cause rebound hyperacidity with overuse"],mnemonic:"Al = Constipation (A-LUMBER bowels). Mg = Diarrhea (Magnesium Moves)."},
{id:"g2",cat:"GI",title:"Proton Pump Inhibitors (PPIs)",subtitle:"Block final step of acid production; -PRAZOLE suffix",generics:["omeprazole","lansoprazole","pantoprazole","esomeprazole","rabeprazole"],trades:["Prilosec","Prevacid","Protonix","Nexium","Aciphex"],drugClass:"Proton pump inhibitor",suffix:"Suffix: -PRAZOLE",mechanism:"Irreversibly inhibits the H+/K+ ATPase (proton pump) enzyme on the parietal cell → blocks the FINAL step of gastric acid secretion → most potent acid suppressor available.",uses:["GERD","Peptic ulcer disease (PUD)","H. pylori (combination therapy)","Zollinger-Ellison syndrome","Prevention of NSAID-induced ulcers"],sideEffects:["Headache","Diarrhea, nausea, vomiting","↑ Risk for pneumonia (respiratory)","↑ Risk for C. difficile infection","Long-term: hypomagnesemia, ↓ calcium → osteoporosis, ↓ Vitamin B12"],patientEd:["Take 30–60 MINUTES before first meal of the day for best effect","Do NOT crush or chew delayed-release capsules","PPIs are for short-term use (overuse linked to side effects)","Not designed to be taken indefinitely"],nursing:["Take 30 min before meals","Monitor Mg, Ca, B12 levels with long-term use","PPIs commonly overprescribed — reassess regularly","Check for drug interactions (warfarin, clopidogrel)"],mnemonic:"PRAZOLE = PRoton pump puts Acid at ZERO. Take 30 min BEFORE eating."},
{id:"g3",cat:"GI",title:"H2 Receptor Antagonists",subtitle:"Block H2 receptors to reduce acid; less potent than PPIs",generics:["famotidine","cimetidine","ranitidine","nizatidine"],trades:["Pepcid","Tagamet","Zantac (discontinued)","Axid"],drugClass:"H2 receptor antagonist",suffix:"Suffix: -TIDINE",mechanism:"Blocks histamine H2 receptors on gastric parietal cells → decreases gastric acid secretion. Less potent than PPIs. INVERSE RELATIONSHIP: ↓ acid = ↓ ulcer formation.",uses:["GERD","Gastric and duodenal ulcers","Heartburn (OTC use)","Zollinger-Ellison syndrome"],sideEffects:["Headache","Diarrhea or constipation","Thrombocytopenia (↓ platelets)","Gynecomastia (cimetidine)"],patientEd:["Avoid large, greasy, spicy meals","Avoid alcohol and smoking","Take before meals for best effect"],nursing:["Monitor CBC (thrombocytopenia risk)","Cimetidine inhibits CYP450 → many drug interactions","Do not take antacids within 1 hour of H2 blockers","Not as potent as PPIs for severe acid suppression"],mnemonic:"-TIDINE = Treat Indigestion Daily. H2 = Half the potency of PPIs"},
{id:"g4",cat:"Sick Call",title:"Loperamide (Imodium)",subtitle:"Antidiarrheal; slows intestinal motility",generics:["loperamide"],trades:["Imodium"],drugClass:"Antidiarrheal (opioid receptor agonist — peripheral)",suffix:"",mechanism:"Acts on opioid receptors in the intestinal wall → SLOWS intestinal motility → decreases stool frequency and increases stool consistency → decreases fluid and electrolyte loss through stool.",uses:["Acute diarrhea","Chronic diarrhea (e.g., IBS)","Ileostomy output reduction"],sideEffects:["Constipation","Abdominal cramping","Drowsiness","Nausea"],patientEd:["If symptoms do not improve after 48 hours → notify HCP","Can cause constipation if overused","Available OTC"],nursing:["Do NOT use in patients with bloody diarrhea or C. diff (can worsen)","Contraindicated in bowel obstruction or ileus","C. diff must be ruled out before using"],mnemonic:"Loperamide = LOPE-ramide = makes intestines LOPE (slow down)"},
{id:"g5",cat:"GI",title:"Lactulose (Cholac)",subtitle:"Osmotic laxative; treats hepatic encephalopathy",generics:["lactulose"],trades:["Cholac","Kristalose","Enulose"],drugClass:"Osmotic laxative / Ammonia detoxicant",suffix:"",mechanism:"Osmotic agent: pulls water into the colon through osmotic pressure → softens stool → promotes bowel movements. Also acidifies colon → traps ammonia (NH3 → NH4+) → reduces ammonia absorption → treats hepatic encephalopathy.",uses:["Constipation","Hepatic encephalopathy (liver disease)","Elevated ammonia levels"],sideEffects:["Loose stools (desired effect for laxative use)","Flatulence and bloating","Nausea, vomiting","Abdominal cramping","Hypokalemia (with excessive use)"],patientEd:["Target: 2–3 soft bowel movements/day for constipation","For hepatic encephalopathy: 3–4 loose stools/day is the goal","Refrigerate after opening","DO NOT give to diabetics without HCP approval (contains sugar)"],nursing:["MONITOR: electrolytes (especially potassium)","Monitor mental status and ammonia levels (hepatic encephalopathy)","FALL RISK precautions (frequent bowel movements)","Do NOT confuse with lactulose – it is NOT the same as lactose"],mnemonic:"Lactulose = LACTU-lose ammonia. 3-4 stools/day = target for hepatic encephalopathy"},
{id:"g6",cat:"GI",title:"Metoclopramide (Reglan)",subtitle:"Prokinetic antiemetic; EPS and tardive dyskinesia risk",generics:["metoclopramide"],trades:["Reglan"],drugClass:"Antiemetic / Dopamine receptor antagonist / GI stimulant",suffix:"",mechanism:"Dopamine receptor antagonist → stimulates GI smooth muscle → ↑ gastric motility and stomach emptying → promotes movement of food through GI tract → relieves nausea/vomiting.",uses:["Gastroparesis","GERD/heartburn","Nausea/vomiting from radiation, anesthesia, opioids","Hiccups (chronic)"],sideEffects:["Fatigue, drowsiness","Dry mouth","Constipation","ADVERSE: Extrapyramidal Symptoms (EPS) – involuntary muscle movements, tongue thrusting, tremors","Tardive Dyskinesia (TD) – irreversible involuntary movements with LONG-TERM use (BLACK BOX WARNING)","Neuroleptic Malignant Syndrome (NMS) – high fever, muscle rigidity (rare but life-threatening)"],patientEd:["Report any abnormal muscle movements IMMEDIATELY","Avoid driving (drowsiness)","Rinse mouth frequently; suck on sugar-free candy for dry mouth","Do NOT use long-term without monitoring"],nursing:["BLACK BOX WARNING: Tardive dyskinesia with long-term use (>12 weeks) — may be irreversible","REPORT and STOP if EPS, TD, or NMS signs appear","Monitor for involuntary movements (tongue, face, extremities)","Avoid in patients with GI obstruction or Parkinson's disease"],mnemonic:"Metoclopramide = METRO-clopramide = MOVES the GI tract. EPS/TD are SIDE TRIPS you don't want to take."},
{id:"g7",cat:"Sick Call",title:"Ondansetron (Zofran)",subtitle:"Serotonin antagonist antiemetic; QT prolongation risk",generics:["ondansetron","granisetron","dolasetron"],trades:["Zofran","Kytril","Anzemet"],drugClass:"Serotonin-5HT3 antagonist (antiemetic)",suffix:"",mechanism:"Blocks serotonin (5-HT3) receptors in the GI tract and chemoreceptor trigger zone (CTZ) in the brain → prevents nausea and vomiting signals from reaching the vomiting center.",uses:["Post-operative nausea/vomiting (PONV)","Chemotherapy-induced nausea/vomiting (CINV)","Radiation-induced nausea","Gastroenteritis-related nausea"],sideEffects:["Headache","Constipation","QT PROLONGATION → risk for Torsades de Pointes (life-threatening arrhythmia)","Serotonin syndrome (if combined with other serotonergic drugs)"],patientEd:["Report palpitations or feeling of rapid/irregular heartbeat","Most effective when given PROPHYLACTICALLY before surgery or chemo","Avoid with other serotonin-affecting medications"],nursing:["MONITOR: ECG, QT interval","Do NOT use in patients with congenital long QT syndrome","Most effective for post-operative and chemotherapy nausea","Can be given IV, IM, PO, or sublingual (ODT)"],mnemonic:"Ondansetron = ON-danger of QT. Zofran = Zero nausea but watch the QT!"},
{id:"g8",cat:"GI",title:"Misoprostol (Cytotec)",subtitle:"Synthetic prostaglandin; GI protectant; causes uterine contractions",generics:["misoprostol"],trades:["Cytotec"],drugClass:"Synthetic prostaglandin (prostaglandin E1 analogue)",suffix:"",mechanism:"Synthetic prostaglandin E1 → inhibits gastric acid secretion + stimulates mucus and bicarbonate secretion → protects gastric mucosa. Also causes uterine contractions (used in obstetrics for cervical ripening/labor induction).",uses:["Prevention of NSAID-induced gastric ulcers","Peptic ulcer disease","Cervical ripening/labor induction (obstetric use)","Management of postpartum hemorrhage"],sideEffects:["Abdominal cramping, diarrhea","GI upset","UTERINE CONTRACTIONS (can cause miscarriage if used in pregnancy — TERATOGENIC)"],patientEd:["Take a pregnancy test BEFORE starting this medication","PREGNANCY CATEGORY X — NEVER use in first trimester","Take with meals to reduce GI side effects","Report abdominal cramping to HCP"],nursing:["VERIFY negative pregnancy test before administration","TERATOGENIC — contraindicated in pregnancy (causes miscarriage)","Report uterine activity","Monitor for GI side effects"],mnemonic:"Misoprostol = MISS-o-prostol = MISScarriage risk. CYTOTEC = CYcle TO End pregnancy (NEVER use in pregnancy for GI)"},
{id:"g9",cat:"Sick Call",title:"Docusate Sodium (Colace)",subtitle:"Stool softener; draws water into stool; prevents straining",generics:["docusate sodium","docusate calcium"],trades:["Colace","Surfak"],drugClass:"Stool softener (emollient laxative)",suffix:"",mechanism:"Surfactant agent → lowers surface tension of stool → allows water and fat to penetrate the stool → softens it → easier to pass without straining.",uses:["Constipation prevention","Post-surgical constipation","Post-MI (prevents Valsalva/straining)","Post-hemorrhoidectomy"],sideEffects:["Diarrhea (if overused)","Abdominal cramping","Throat irritation (liquid form)"],patientEd:["Drink plenty of fluids (at least 8 glasses/day)","Eat high-fiber diet","Do NOT strain during bowel movements","Does NOT stimulate bowel — it only softens stool"],nursing:["Do NOT use with mineral oil (mineral oil absorption ↑ → toxicity)","Not for paralytic ileus or bowel obstruction","Results typically in 1–3 days","Often given prophylactically post-surgery, post-MI"],mnemonic:"Docusate = DOO-casate = makes the DOO easier to pass"},
// ── CNS ──────────────────────────────────────────────────────────────────────
{id:"c1",cat:"CNS",title:"Serotonin 5-HT Receptor Agonists (Triptans)",subtitle:"Treat acute migraines; vasoconstrict cranial blood vessels",generics:["sumatriptan","almotriptan","eletriptan","rizatriptan","zolmitriptan"],trades:["Imitrex","Axert","Relpax","Maxalt","Zomig"],drugClass:"Serotonin agonist (5-HT1B/1D agonist)",suffix:"Suffix: -TRIPTAN",mechanism:"Activates serotonin (5-HT1B/1D) receptors in cranial blood vessels → vasoconstriction of dilated cranial arteries → inhibits neuropeptide release → breaks migraine cycle. Dilation of cranial arteries = migraine pain; triptans reverse this.",uses:["Acute migraine attacks","Cluster headaches"],sideEffects:["↑ Blood pressure","Dizziness","Fatigue/drowsiness","Burning/tingling at injection site","Chest tightness (rare — coronary vasospasm)"],patientEd:["Take at the FIRST sign of migraine","NOT for migraine prevention — for acute treatment ONLY","Do NOT take prophylactically","Avoid in patients with cardiovascular disease"],nursing:["CONTRAINDICATED in: HTN, CAD, PVD, history of stroke (vasoconstrictive effect)","Do not combine with MAOIs or SSRIs (serotonin syndrome risk)","Monitor BP and cardiovascular status"],mnemonic:"TRIPTAN = TRIggered migraine pain ends. 'Trip to the -TRIPTAN to treat the trippy headache'"},
{id:"c2",cat:"CNS",title:"SSRIs (Selective Serotonin Reuptake Inhibitors)",subtitle:"First-line antidepressants; 4–6 weeks to full effect",generics:["fluoxetine","sertraline","paroxetine","escitalopram","citalopram"],trades:["Prozac","Zoloft","Paxil","Lexapro","Celexa"],drugClass:"Antidepressant (SSRI)",suffix:"Suffixes: -OXETINE, -ALINE, -PRAM",mechanism:"Block serotonin reuptake transporter (SERT) → ↑ serotonin availability in synapse → improved mood, reduced anxiety. Takes 4–6 weeks for therapeutic effect.",uses:["Major depressive disorder (MDD)","Anxiety disorders (GAD, panic disorder)","OCD","PTSD","Eating disorders (bulimia)"],sideEffects:["Sexual dysfunction (↓ libido, orgasm difficulty)","GI upset (nausea, vomiting, diarrhea) — especially initially","Weight gain (especially paroxetine)","Insomnia or drowsiness","ADVERSE: SEROTONIN SYNDROME (life-threatening — agitation, diaphoresis, ↑ HR/BP/temp, muscle rigidity)"],patientEd:["Takes 4–6 WEEKS for full therapeutic effect — do NOT stop early","Do NOT stop abruptly — must be tapered (discontinuation syndrome)","Take in the morning (may cause insomnia)","Report worsening depression or suicidal thoughts IMMEDIATELY"],nursing:["BLACK BOX WARNING: ↑ suicidal ideation in children/adolescents/young adults","Monitor for suicidal ideation, behavioral changes","Do NOT combine with MAOIs (serotonin syndrome)","Do NOT combine with St. John's Wort"],mnemonic:"3 S's: Sexual dysfunction, Stomach upset, Serotonin syndrome. 4-6 weeks. NO MAOIs."},
{id:"c3",cat:"CNS",title:"SNRIs & NDRIs",subtitle:"Depression + pain (duloxetine); smoking cessation (bupropion)",generics:["venlafaxine","duloxetine","desvenlafaxine","bupropion"],trades:["Effexor","Cymbalta","Pristiq","Wellbutrin","Zyban"],drugClass:"Antidepressant (SNRI/NDRI)",suffix:"",mechanism:"SNRIs (venlafaxine, duloxetine): block reuptake of both serotonin AND norepinephrine → ↑ both neurotransmitters. NDRIs (bupropion): block reuptake of norepinephrine AND dopamine.",uses:["Major depressive disorder","Anxiety disorders (venlafaxine)","Fibromyalgia and chronic neuropathic pain (duloxetine)","ADHD (bupropion)","Smoking cessation (bupropion/Zyban)"],sideEffects:["GI upset","Drowsiness","Sexual dysfunction (less than SSRIs)","Hypertension (venlafaxine at higher doses)","Seizures at high doses (bupropion — lowers seizure threshold)"],patientEd:["Do NOT stop abruptly — taper off","Report palpitations (HTN risk)","Bupropion: avoid in eating disorders (seizure risk)"],nursing:["Do NOT combine with MAOIs","Monitor BP (especially venlafaxine)","Monitor for suicidal ideation","Bupropion CONTRAINDICATED in eating disorders and seizure history"],mnemonic:"SNRIs = Serotonin + Norepinephrine. Cymbalta = Chronic pain helper"},
{id:"c4",cat:"CNS",title:"Tricyclic Antidepressants (TCAs)",subtitle:"Older antidepressants; anticholinergic side effects; narrow TI",generics:["amitriptyline","nortriptyline","imipramine","doxepin","clomipramine"],trades:["Elavil","Pamelor","Tofranil","Sinequan","Anafranil"],drugClass:"Antidepressant (TCA)",suffix:"Suffix: -TYLINE, -PRAMINE",mechanism:"Block reuptake of both serotonin AND norepinephrine (with stronger norepinephrine effect). Also block muscarinic (anticholinergic), histamine, and alpha-1 receptors → many side effects.",uses:["Major depression (not first-line)","OCD (clomipramine)","Chronic neuropathic pain","Migraine prophylaxis","Bedwetting in children (imipramine)"],sideEffects:["CANT: Can't See (blurred vision, dry eyes), Can't Pee (urinary retention), Can't Spit (dry mouth), Can't Poop (constipation)","Cardiotoxicity: arrhythmias, tachycardia, hypotension","FALL RISK: sedation, orthostatic hypotension","LETHAL in overdose (wide QRS, arrhythmia)"],patientEd:["Change positions slowly (orthostatic hypotension)","Do NOT stop abruptly","Take at bedtime (sedating)","Avoid alcohol"],nursing:["Monitor cardiac status (EKG/ECG) — QRS widening in toxicity","Narrow therapeutic index — can be lethal in overdose","Do NOT use in patients with bipolar disorder (may trigger mania)","Overdose treatment: sodium bicarbonate for cardiac toxicity"],mnemonic:"CANT (same as anticholinergics). TCA Toxicity = Wide QRS + Arrhythmia"},
{id:"c5",cat:"CNS",title:"NSAIDs (Nonsteroidal Anti-inflammatory Drugs)",subtitle:"Anti-inflammatory + analgesic + antipyretic; GI bleed risk",generics:["ibuprofen","naproxen","ketorolac","indomethacin","celecoxib","diclofenac"],trades:["Advil","Motrin","Aleve","Toradol","Indocin","Celebrex","Voltaren"],drugClass:"Analgesic / Anti-inflammatory / Antipyretic",suffix:"Suffix: -PROFEN, -AC, -OLC",mechanism:"Inhibits COX-1 and COX-2 enzymes → blocks prostaglandin synthesis → decreases inflammation, pain, and fever. COX-1 inhibition also reduces GI mucosal protection → GI irritation/bleeding.",uses:["Mild to moderate pain","Fever","Inflammatory conditions (OA, RA)","Dysmenorrhea","Post-operative pain (ketorolac IV)"],sideEffects:["GI BLEED (most important — black tarry stools)","GI upset (nausea, heartburn)","Nephrotoxicity (↓ renal blood flow)","Hypertension","↑ Risk for MI/stroke (especially COX-2 inhibitors)","Platelet inhibition → bleeding risk"],patientEd:["Take WITH food or milk to reduce GI upset","Report black/tarry stools or blood in stool","Report decreased urine output","Avoid alcohol"],nursing:["AVOID in: asthma (aspirin-sensitive), bleeding disorders, renal impairment, pregnant women (3rd trimester)","Monitor BUN, creatinine (nephrotoxicity)","May give PPI or misoprostol to protect stomach lining","Do NOT give with anticoagulants without caution"],mnemonic:"-PROFEN/-AC. NSAIDs = No Stomach Agrees with IDentical Drugs. GI BLEED + KIDNEY damage"},
{id:"c6",cat:"Sick Call",title:"Acetaminophen (Tylenol)",subtitle:"Analgesic + antipyretic; HEPATOTOXIC — max 4g/day",generics:["acetaminophen"],trades:["Tylenol","Panadol"],drugClass:"Nonopioid analgesic / Antipyretic",suffix:"",mechanism:"Inhibits COX enzymes (mainly in CNS, NOT peripherally) → reduces fever and pain signals. Does NOT have significant anti-inflammatory or antiplatelet effects. Does NOT protect GI tract but also does NOT irritate it.",uses:["Mild to moderate pain","Fever (antipyretic)","Safe option in patients who cannot take NSAIDs (GI issues, asthma)"],sideEffects:["HEPATOTOXICITY (liver damage — #1 cause of acute liver failure in the US)","Hepatic necrosis in overdose","Anorexia","Stevens-Johnson syndrome (rare)"],patientEd:["Maximum dose: 1,000 mg per dose / 4,000 mg per day (3,000 mg/day in elderly or alcoholics)","AVOID alcohol (↑ hepatotoxicity risk)","Check ALL medications for acetaminophen (many combo OTC drugs contain it)","Report signs of liver damage: jaundice, dark urine, RUQ pain"],nursing:["Monitor LFTs (hepatotoxicity)","Antidote for overdose: N-ACETYLCYSTEINE (Acetadote) — give within 8–10 hrs","Many combination products contain acetaminophen — check ALL medications to avoid cumulative overdose","Contraindicated in hepatic impairment"],mnemonic:"Acetaminophen = A-CETA-min-ophen = Attacks CEllular TApeworm... no. MAX 4g/day. Antidote = N-Acetylcysteine"},
{id:"c7",cat:"Sick Call",title:"Aspirin (Bayer Aspirin)",subtitle:"NSAID + antiplatelet; anticoagulant; Reye's syndrome in kids",generics:["aspirin","acetylsalicylic acid (ASA)"],trades:["Bayer Aspirin","Ecotrin","Bufferin"],drugClass:"Acetylsalicylic acid (NSAID / Antiplatelet)",suffix:"",mechanism:"IRREVERSIBLY inhibits COX-1 and COX-2 enzymes → blocks thromboxane A2 in platelets → prevents platelet aggregation (antiplatelet) → decreases pain/inflammation/fever. Platelet effect lasts entire platelet lifespan (7–10 days).",uses:["Mild-moderate pain and fever","MI prophylaxis and acute MI (antiplatelet)","Stroke (TIA) prophylaxis","Cardioprotection (low-dose 81 mg)"],sideEffects:["GI bleeding (black, tarry stools)","Nausea, GI upset","INTERNAL BLEEDING (bright red = active; coffee grounds = old)","Tinnitus (ringing in ears) = sign of toxicity","Reye's syndrome in children with viral illness (encephalopathy + liver failure)"],patientEd:["Do NOT give to children with viral illness (chickenpox, flu) — Reye's syndrome risk","STOP aspirin 7–10 days before any surgery","Report black/tarry stools, unusual bleeding","Report ringing in ears (toxicity)"],nursing:["DO NOT give to children < 18 with viral illness","Vitamin K deficiency → avoid aspirin","Monitor for GI bleeding","Do not combine with anticoagulants without caution","Low-dose (81 mg) for cardioprotection"],mnemonic:"Aspirin = ASPIRE to save the heart. REYE'S = NO kids with viral illness. STOP 7-10 days before surgery."},
{id:"c8",cat:"CNS",title:"Opioids",subtitle:"Strong analgesics; respiratory depression risk; naloxone antidote",generics:["morphine","hydromorphone","hydrocodone","oxycodone","fentanyl","codeine","tramadol","meperidine"],trades:["MS Contin","Dilaudid","Vicodin","OxyContin","Duragesic","Demerol","Ultram"],drugClass:"Opioid analgesic",suffix:"Suffix: -DONE, -ONE, -INE (oxycodone, hydromorphone, morphine)",mechanism:"Binds to mu (μ) opioid receptors in the CNS → inhibits pain signals → produces analgesia, sedation, euphoria, respiratory depression. Most effective analgesic available for severe pain.",uses:["Moderate to severe pain","Post-operative pain","Cancer pain","Dyspnea in palliative care","Cough suppression (codeine)","End-of-life comfort"],sideEffects:["RESPIRATORY DEPRESSION (most dangerous — monitor RR)","Constipation (MOST COMMON side effect)","Nausea/vomiting","Sedation","Hypotension (especially with IV)","Bradycardia","Urinary retention","Pruritus (itching)","Physical dependence with long-term use"],patientEd:["Fruits, Fiber & Fluids — for constipation","Do NOT drive or operate machinery","Do NOT combine with alcohol, benzodiazepines (↑ respiratory depression)","Keep naloxone (Narcan) at home if prescribed","Report respiratory rate < 12/min"],nursing:["STOP if RR < 12 breaths/min","Have naloxone (Narcan) AVAILABLE at all times","Monitor: RR, SpO2, BP, level of consciousness","ANTIDOTE: Naloxone (Narcan) — reverses opioid effects","Raise side rails; fall precautions","Scheduled bowel regimen to prevent constipation"],mnemonic:"LOW (Opioid side effects): LOW vital signs, LOW respiratory rate. Antidote = Naloxone (Narcan). 'No Air, Can't poop, Puking, Sleepy'"},
// ── CARDIOVASCULAR ───────────────────────────────────────────────────────────
{id:"v1",cat:"Cardiovascular",title:"Antihypertensive Medications Overview",subtitle:"ABCD mnemonic for antihypertensive classes",generics:[],trades:[],drugClass:"Antihypertensive Overview",suffix:"ACE: -PRIL | ARBs: -SARTAN | Beta-blockers: -OLOL | CCBs: -DIPINE",mechanism:"Four main classes: A = ACE inhibitors (block angiotensin converting enzyme), B = Beta-blockers (block beta-adrenergic receptors), C = Calcium Channel Blockers (block calcium entry into smooth muscle), D = Diuretics (reduce fluid volume).",uses:["Hypertension (HTN)","Heart failure","MI prevention"],sideEffects:[],patientEd:["Never stop antihypertensive medications abruptly (rebound hypertension)","Take blood pressure daily at same time each day","Report BP > 180/120 (hypertensive emergency)"],nursing:["Check BP BEFORE giving antihypertensives","Hold if BP < 90/60 (per protocol)","Monitor for orthostatic hypotension"],mnemonic:"ABCD: ACE inhibitors, Beta-blockers, Calcium channel blockers, Diuretics"},
{id:"v2",cat:"Cardiovascular",title:"Orthostatic Hypotension",subtitle:"BP drop when rising; FALL RISK with antihypertensives",generics:[],trades:[],drugClass:"Cardiovascular Concept (Side Effect)",suffix:"",mechanism:"Drop in blood pressure (≥20 mmHg systolic or ≥10 mmHg diastolic) when moving from lying → sitting → standing. Caused by inadequate peripheral vasoconstriction response. Common side effect of antihypertensives.",uses:["Understanding and preventing falls with antihypertensive use"],sideEffects:[],patientEd:["RISE SLOWLY: dangle legs at side of bed before standing","Sit on the edge of the bed for 1–2 minutes before standing","Change positions in stages: lying → sitting → standing","Compression stockings may help"],nursing:["FALL RISK — institute fall precautions","Measure BP in lying, sitting, and standing positions","Occurs commonly with: ACE inhibitors, ARBs, alpha blockers, beta blockers, CCBs, diuretics, TCAs"],mnemonic:"DANGLE first before standing — prevent the FALL"},
{id:"v3",cat:"Cardiovascular",title:"Rebound Hypertension",subtitle:"Sudden BP spike when antihypertensive stopped abruptly",generics:[],trades:[],drugClass:"Cardiovascular Concept (Complication)",suffix:"",mechanism:"Sudden discontinuation of antihypertensive medications → compensatory surge in BP above baseline. Most dangerous with beta-blockers (especially propranolol) and clonidine.",uses:["Understanding why antihypertensives must never be stopped suddenly"],sideEffects:[],patientEd:["NEVER stop blood pressure medications abruptly","If a dose is missed, take it as soon as remembered (unless near time for next dose)","Contact HCP before stopping any antihypertensive"],nursing:["Educate ALL patients on antihypertensives about rebound effect","Discontinue by TAPERING gradually","Most dangerous with: beta-blockers, clonidine, calcium channel blockers"],mnemonic:"Stopped suddenly = BP spikes SUDDENLY. Taper, don't stop."},
{id:"v4",cat:"Cardiovascular",title:"ACE Inhibitors",subtitle:"Treat HTN & HF; dry cough; TERATOGENIC",generics:["lisinopril","enalapril","ramipril","captopril","benazepril","quinapril"],trades:["Prinivil","Vasotec","Altace","Capoten","Lotensin","Accupril"],drugClass:"Antihypertensive (ACE inhibitor)",suffix:"Suffix: -PRIL",mechanism:"Inhibits angiotensin-converting enzyme (ACE) → prevents conversion of angiotensin I → angiotensin II → ↓ vasoconstriction + ↓ aldosterone secretion → ↓ Na/H2O retention → ↓ BP. Also prevents bradykinin breakdown → causes DRY COUGH.",uses:["Hypertension","Heart failure","Diabetic nephropathy (kidney protection)","Post-MI cardioprotection"],sideEffects:["DRY HACKING COUGH (#1 reason for discontinuation)","Angioedema (life-threatening swelling of face/throat — STOP immediately)","Hyperkalemia (↑ K+)","Orthostatic hypotension","Dizziness","Nephrotoxicity (first dose effect with renal artery stenosis)"],patientEd:["Change positions slowly (orthostatic hypotension)","Report dry cough — may need to switch to ARB","Report swelling of face/throat (angioedema) — EMERGENCY","Avoid potassium supplements and potassium-sparing diuretics","TERATOGENIC — must avoid in pregnancy"],nursing:["Hold if SBP < 90 or as ordered","Monitor: BUN, creatinine (renal function), K+ levels, BP, urine output","Normal BUN: 7–20 mg/dL; Creatinine: 0.6–1.2 mg/dL","TERATOGENIC — absolutely contraindicated in pregnancy","Angioedema = STOP medication + emergency airway management"],mnemonic:"ACE: Angioedema, Cough, Elevated K+. PRIL = Pregnancy Risk = Immediately Lethal. Suffix: -PRIL"},
{id:"v5",cat:"Cardiovascular",title:"ARBs (Angiotensin II Receptor Blockers)",subtitle:"Like ACE inhibitors but NO dry cough; still TERATOGENIC",generics:["losartan","valsartan","candesartan","irbesartan","olmesartan"],trades:["Cozaar","Diovan","Atacand","Avapro","Benicar"],drugClass:"Antihypertensive (ARB)",suffix:"Suffix: -SARTAN",mechanism:"Directly blocks angiotensin II AT1 receptors → prevents vasoconstriction + prevents aldosterone release → ↓ BP. Does NOT inhibit ACE enzyme → does NOT prevent bradykinin breakdown → NO dry cough (key difference from ACE inhibitors).",uses:["Hypertension","Heart failure","Diabetic nephropathy","Post-MI (in patients who cannot tolerate ACE inhibitors)"],sideEffects:["Hypotension","Dizziness","Hyperkalemia (↑ K+)","Fetal harm (TERATOGENIC)","NOTE: NO dry cough (unlike ACE inhibitors)"],patientEd:["ARBs are alternative for patients who cannot tolerate ACE inhibitor cough","TERATOGENIC — must avoid in pregnancy","Report dizziness or low BP signs","Avoid potassium supplements"],nursing:["Monitor: BP, renal function (BUN, creatinine), K+ levels","TERATOGENIC — absolutely contraindicated in pregnancy (same as ACE inhibitors)","Preferred over ACE inhibitors when patient has ACE inhibitor-induced cough","Less risk of angioedema than ACE inhibitors"],mnemonic:"-SARTAN = Same as ACE-PRIL but No Cough. Both TERATOGENIC. ARBs = ACE's Replacement for the cough."},
{id:"v6",cat:"Cardiovascular",title:"Alpha-2 Adrenergic Agonists",subtitle:"Treat HTN; reduce CNS sympathetic outflow; rebound HTN if stopped",generics:["clonidine","methyldopa"],trades:["Catapres","Aldomet"],drugClass:"Antihypertensive (Alpha-2 agonist)",suffix:"",mechanism:"Stimulates alpha-2 receptors in the CNS → reduces sympathetic outflow from brain → ↓ norepinephrine release → ↓ heart rate + ↓ vascular resistance → ↓ BP. Works in the BRAIN to lower BP.",uses:["Hypertension","ADHD (clonidine)","Alcohol/opioid withdrawal","Methyldopa: hypertension in pregnancy (safe in pregnancy)"],sideEffects:["Drowsiness (sedation)","Dry mouth","Orthostatic hypotension","Depression","Rebound hypertension if stopped ABRUPTLY"],patientEd:["Do NOT stop clonidine suddenly (severe rebound HTN)","If a dose is missed, resume as soon as possible","Avoid alcohol (increases sedation)"],nursing:["Never stop clonidine abruptly — taper","Monitor BP (especially when changing positions)","Methyldopa is safe in pregnancy (unlike most antihypertensives)","Drowsiness may impair daily functioning"],mnemonic:"Clonidine = CLONiDINE the brain (central alpha-2). Stop suddenly = CLONIDINE REBOUNDS HTN"},
{id:"v7",cat:"Cardiovascular",title:"Beta-Adrenergic Blockers (Beta Blockers)",subtitle:"Treat HTN, angina, HF; bronchoconstriction risk; -OLOL suffix",generics:["metoprolol","atenolol","carvedilol","propranolol","labetalol","bisoprolol"],trades:["Lopressor","Toprol XL","Tenormin","Coreg","Inderal","Trandate","Zebeta"],drugClass:"Antihypertensive / Antidysrhythmic (Beta blocker)",suffix:"Suffix: -OLOL",mechanism:"Blocks beta-adrenergic receptors. Beta-1 (heart & kidneys): ↓ HR, ↓ contractility, ↓ renin → ↓ BP. Beta-2 (lungs): bronchoconstriction (problem in asthma). Slows the heart and provides a more effective beat.",uses:["Hypertension","Stable angina","Heart failure (chronic/compensated)","Tachyarrhythmias (SVT, A-fib)","Post-MI (cardioprotective)","Anxiety (propranolol)"],sideEffects:["Bradycardia (↓ HR)","Hypotension","BRONCHOCONSTRICTION (dangerous in asthma/COPD — AVOID)","MASKS hypoglycemia symptoms in diabetics (↑ HR masked)","Fatigue/drowsiness","Sexual dysfunction","Rebound hypertension if stopped abruptly"],patientEd:["NEVER stop abruptly (rebound HTN, angina, MI risk)","Monitor pulse daily — hold if HR < 60","Change positions slowly","Report wheezing or difficulty breathing"],nursing:["Hold if HR < 60 or SBP < 90 (per protocol)","CONTRAINDICATED in: asthma/COPD (bronchoconstriction), heart block, cardiogenic shock","MASKS hypoglycemia signs in diabetic patients","Must be TAPERED off — never stopped abruptly","Monitor for bradycardia and hypotension"],mnemonic:"B's of Beta Blockers: Bradycardia, Bronchospasm, Blood pressure low, Blood sugar masked, Be careful in asthma"},
{id:"v8",cat:"Cardiovascular",title:"Calcium Channel Blockers (CCBs)",subtitle:"Treat HTN, angina, dysrhythmias; -DIPINE suffix; avoid grapefruit",generics:["amlodipine","nifedipine","verapamil","diltiazem"],trades:["Norvasc","Procardia","Calan SR","Cardizem","Tiazac"],drugClass:"Antihypertensive / Antidysrhythmic (Calcium channel blocker)",suffix:"Suffix: -DIPINE",mechanism:"Inhibit calcium ion entry into vascular smooth muscle and cardiac muscle cells → blood vessels RELAX → ↓ peripheral resistance → ↓ BP. Also slows SA/AV node conduction (verapamil, diltiazem) → ↓ HR.",uses:["Hypertension","Stable and variant (Prinzmetal) angina","Dysrhythmias (verapamil, diltiazem for rate control)","Raynaud's phenomenon"],sideEffects:["Orthostatic hypotension and dizziness","Peripheral edema (especially amlodipine)","Flushing","Headache","Constipation","Reflex tachycardia (dihydropyridines like amlodipine)","Bradycardia/heart block (verapamil, diltiazem)"],patientEd:["Change positions slowly (orthostatic hypotension)","Do NOT eat GRAPEFRUIT or drink grapefruit juice (↑ drug concentration → toxicity)","Never stop abruptly (rebound angina/HTN)","Fruits, Fiber & Fluids for constipation","Elevate legs for peripheral edema"],nursing:["GRAPEFRUIT JUICE = FORBIDDEN (inhibits CYP3A4 → ↑ drug levels)","Hold if HR < 60 (verapamil/diltiazem) or SBP < 90","Do NOT combine verapamil/diltiazem with beta-blockers (severe bradycardia/heart block)","Monitor for constipation; promote bowel routine"],mnemonic:"-DIPINE = DiPIctures of blood vessels DIlating. GRAPEFRUIT = FORBIDDEN with CCBs"},
// ── ANALGESICS & NSAIDs (from Analgesics_NSAIDs_Flashcards) ─────────────────
{id:"a1",cat:"Sick Call",title:"Ibuprofen (Advil / Motrin)",subtitle:"NSAID — pain, fever, inflammation — take with food",generics:["ibuprofen"],trades:["Advil","Motrin"],drugClass:"NSAID (non-selective COX inhibitor)",suffix:"Suffix: -PROFEN",mechanism:"Non-selective COX inhibitor. Blocks COX-1 and COX-2 enzymes → reduces prostaglandin production → decreases pain, fever, and inflammation throughout the body.",uses:["Mild to moderate pain relief","Fever reduction","Inflammation (arthritis, sprains, dysmenorrhea)"],sideEffects:["Stomach pain, heartburn, nausea","GI bleeding risk (black or tarry stools)","Long-term use: elevated blood pressure and kidney damage"],patientEd:["Take 400–800 mg PO every 6–8 hours WITH food to protect the stomach","Do not exceed 3,200 mg in 24 hours","Report black or tarry stools immediately","Avoid in 3rd trimester of pregnancy"],nursing:["Contraindicated in: active stomach ulcers or GI bleeding, severe kidney disease, and pregnancy 3rd trimester","Monitor renal function and BP with prolonged use"],mnemonic:"iBUPROFen — Max 3,200 mg/day. Take WITH food. Watch for GI BLEED."},
{id:"a2",cat:"Sick Call",title:"Ketorolac (Toradol)",subtitle:"Potent NSAID — IM injection — MAX 5 days total",generics:["ketorolac"],trades:["Toradol"],drugClass:"NSAID / Non-opioid analgesic",suffix:"",mechanism:"Potent NSAID that aggressively blocks prostaglandin synthesis via COX-1 and COX-2 inhibition → powerful analgesic and anti-inflammatory effect without opioid activity.",uses:["Short-term moderate to severe acute pain","Post-operative pain","Pain when opioids should be avoided"],sideEffects:["Severe GI irritation and nausea","Dizziness","Acute kidney injury if patient is dehydrated"],patientEd:["Standard dose: 30 mg IM","Do NOT use for more than 5 days — GI and kidney risk increases sharply","Stay well hydrated while on this medication"],nursing:["Contraindicated in: active bleeding, high bleeding risk, kidney failure, or concurrent NSAIDs","Max duration: 5 days across ALL routes combined (IM + IV + PO)"],mnemonic:"Toradol = TORA-dol = Tough pain tamed. 30 mg IM. MAX 5 DAYS total."},
{id:"a3",cat:"Sick Call",title:"Naproxen Sodium (Aleve)",subtitle:"Long-acting NSAID — every 12 hours dosing",generics:["naproxen sodium"],trades:["Aleve","Anaprox"],drugClass:"NSAID (non-selective COX inhibitor)",suffix:"",mechanism:"Non-selective COX inhibitor. Blocks prostaglandin production → reduces pain and inflammation. Longer half-life than ibuprofen → requires only twice-daily dosing.",uses:["Pain relief","Fever reduction","Inflammation control (arthritis, menstrual cramps)"],sideEffects:["GI upset and heartburn","Drowsiness","Stomach bleeding with prolonged use"],patientEd:["Take 220–500 mg PO every 12 hours","Do not exceed 1,000–1,250 mg daily","Take WITH food to reduce GI upset"],nursing:["Contraindicated in: history of GI bleeding, active ulcers, severe kidney dysfunction, and late-stage pregnancy","Key difference from ibuprofen: every 12 HOURS dosing"],mnemonic:"NAProxen = NAPS every 12 hours. Long-acting — one dose lasts the day."},
{id:"a4",cat:"Sick Call",title:"Diclofenac 1% Gel (Voltaren)",subtitle:"Topical NSAID — targeted joint pain — minimal GI risk",generics:["diclofenac sodium"],trades:["Voltaren Gel"],drugClass:"Topical NSAID",suffix:"",mechanism:"Topical COX inhibitor → stops the inflammatory cascade locally at the application site. Minimal systemic absorption compared to oral NSAIDs → lower GI and renal risk.",uses:["Targeted joint and muscle pain relief","Osteoarthritis of the knee, hand, or elbow","Patients with GI history who need NSAID therapy"],sideEffects:["Local skin irritation at the application site","Minimal GI effects due to low systemic absorption"],patientEd:["Apply 2–4 grams directly into the affected joint up to 4 times daily","Wash hands after applying","Do not cover with tight bandages or occlusive dressings"],nursing:["Contraindicated in: severe liver disease, active stomach ulcers, or hypersensitivity to other NSAIDs","Best option for patients who cannot tolerate oral NSAIDs"],mnemonic:"TOPICAL = No stomach risk. Voltaren Gel = targeted joint pain without GI harm."},
// ── DECONGESTANTS & ANTIHISTAMINES (from Decongestants_Cold_Flashcards) ──────
{id:"d1",cat:"Sick Call",title:"Pseudoephedrine (Sudafed)",subtitle:"Oral decongestant — stimulant side effects — behind-the-counter",generics:["pseudoephedrine"],trades:["Sudafed"],drugClass:"Sympathomimetic / Oral decongestant",suffix:"",mechanism:"Alpha-adrenergic agonist. Stimulates alpha receptors in the respiratory tract → vasoconstriction of swollen nasal mucous membranes → opens the airway and promotes drainage.",uses:["Nasal and sinus congestion","Common cold and allergic rhinitis"],sideEffects:["Insomnia and jitteriness","Anxiety","Tachycardia and elevated blood pressure"],patientEd:["Take 30–60 mg PO every 4–6 hours","Do not exceed 240 mg in 24 hours","Must be purchased from behind the pharmacy counter — photo ID required"],nursing:["Contraindicated in: severe hypertension, severe coronary artery disease, or concurrent MAOI use","Monitor BP and HR — sympathomimetic effects"],mnemonic:"PSEUDOephedrine = PSEUDO-stimulant. Makes your heart RACE and nose CLEAR."},
{id:"d2",cat:"Sick Call",title:"Oxymetazoline (Afrin)",subtitle:"Nasal spray — rapid relief — MAX 3–5 days — rebound risk",generics:["oxymetazoline"],trades:["Afrin"],drugClass:"Alpha-adrenergic agonist (topical nasal decongestant)",suffix:"",mechanism:"Direct-acting alpha-adrenergic agonist → causes intense, localized vasoconstriction of the nasal mucosa → reduces swelling immediately within minutes of use.",uses:["Rapid short-term relief of severe nasal congestion","Common cold and acute sinusitis"],sideEffects:["Burning, stinging, or dryness in the nose","Rebound congestion (rhinitis medicamentosa) if overused — congestion returns WORSE than before"],patientEd:["Use 2–3 sprays in each nostril every 10–12 hours","NEVER use for more than 3–5 days — rebound congestion will develop","If congestion worsens after stopping, that is the rebound effect (rhinitis medicamentosa)"],nursing:["Use with caution in patients with hypertension or heart disease","Rhinitis medicamentosa = hallmark complication of overuse"],mnemonic:"Afrin = AFRAID of rebound! 3–5 DAYS MAX. Stop and congestion bounces back."},
{id:"d3",cat:"Sick Call",title:"Diphenhydramine (Benadryl)",subtitle:"1st-gen antihistamine — SEDATING — anaphylaxis adjunct",generics:["diphenhydramine"],trades:["Benadryl"],drugClass:"First-generation antihistamine (H1-receptor antagonist)",suffix:"Suffix: -RAMINE",mechanism:"H1-receptor antagonist. Blocks histamine from binding to receptors → reduces allergic symptoms. Readily crosses the blood-brain barrier → causes significant sedation (anticholinergic effects).",uses:["Allergic reactions and urticaria","Anaphylaxis (adjunct to epinephrine — NOT a replacement)","Severe itching","Motion sickness"],sideEffects:["Drowsiness and dizziness (significant)","Dry mouth (anticholinergic)","Blurred vision","Urinary retention"],patientEd:["Take 25–50 mg PO, IM, or IV every 4–6 hours","Do NOT drive or operate machinery — causes significant sedation","Do NOT take with alcohol","ALWAYS give epinephrine FIRST in anaphylaxis — Benadryl is adjunct only"],nursing:["Contraindicated in: acute asthma attacks, narrow-angle glaucoma, and urinary obstruction","FALL RISK in elderly patients — avoid if possible","First-generation = crosses BBB = sedating"],mnemonic:"BENADRYL = BED Now After DRooping Your Lids. 1st gen = SEDATING. Epi FIRST in anaphylaxis."},
{id:"d4",cat:"Sick Call",title:"Loratadine (Claritin)",subtitle:"2nd-gen antihistamine — NON-sedating — once daily",generics:["loratadine"],trades:["Claritin"],drugClass:"Second-generation antihistamine (H1-receptor antagonist)",suffix:"Suffix: -ADINE",mechanism:"Long-acting H1-receptor antagonist. Blocks peripheral histamine receptors but does NOT cross the blood-brain barrier effectively → avoids CNS depression and sedation.",uses:["Daily management of seasonal allergies","Allergic rhinitis","Chronic hives (urticaria)"],sideEffects:["Generally well-tolerated","Rare: headache, dry mouth, or mild fatigue"],patientEd:["Take 10 mg PO once daily","Non-sedating — safe during the day while working or driving","Can be taken on an ongoing daily basis for allergy control"],nursing:["Contraindicated in: severe liver impairment (requires dose reduction or every-other-day dosing)","Preferred antihistamine when the patient must remain alert and functional"],mnemonic:"Loratadine = ClaRITIN = CLARITY (non-sedating). 10 mg once daily. Stay CLEAR-headed."},
{id:"d5",cat:"Sick Call",title:"Cetirizine (Zyrtec)",subtitle:"2nd-gen antihistamine — faster onset — mild sedation possible",generics:["cetirizine"],trades:["Zyrtec"],drugClass:"Second-generation antihistamine (H1-receptor antagonist)",suffix:"Suffix: -IZINE",mechanism:"Selective H1-receptor antagonist. Blocks peripheral histamine. Crosses the blood-brain barrier slightly more than loratadine but much less than diphenhydramine → faster symptom relief with mild sedation risk.",uses:["Seasonal allergies and allergic rhinitis","Hives (urticaria)","Year-round allergy management"],sideEffects:["Mild drowsiness or sedation (more common than with loratadine)","Dry mouth and fatigue"],patientEd:["Take 10 mg PO once daily","May cause mild drowsiness — take in the evening if sensitive","Non-addictive and safe for long-term daily use"],nursing:["Contraindicated in: hypersensitivity to cetirizine or hydroxyzine","Use with caution in severe kidney impairment","Slightly more sedating than loratadine — advise caution when driving"],mnemonic:"CetiRIZINE = ZYRTEC. ZZZ-tec (slightly sedating). Faster onset than Claritin."},
// ── SPECIFIC GI MEDICATIONS (from GI_Meds_Flashcards) ───────────────────────
{id:"gi1",cat:"Sick Call",title:"Bismuth Subsalicylate (Pepto-Bismol)",subtitle:"GI protectant — diarrhea, heartburn — black stool warning",generics:["bismuth subsalicylate"],trades:["Pepto-Bismol","Kaopectate"],drugClass:"Antidiarrheal / GI protectant / Antacid",suffix:"",mechanism:"Coats the stomach lining → protects against irritants. Mild antimicrobial properties. Reduces intestinal inflammation and fluid secretion.",uses:["Mild diarrhea (including traveler's diarrhea)","Heartburn and indigestion","Nausea and upset stomach"],sideEffects:["Harmless blackening of the tongue and stool (can be confused with GI bleed — always warn the patient)"],patientEd:["Take 524 mg (2 tablets or 30 mL) every 30–60 minutes as needed","Do not exceed 8 doses in 24 hours","WARNING: tongue and stool will turn BLACK — this is HARMLESS"],nursing:["Contraindicated in: aspirin/salicylate allergy, bleeding disorders, and children with viral infections (Reye's syndrome risk)","Contains salicylate — treat like aspirin regarding interactions and contraindications"],mnemonic:"PEPTO = Paints Everything Pitch-black Temporarily. HARMLESS! Watch for Reye's in kids."},
{id:"gi2",cat:"Sick Call",title:"Famotidine (Pepcid)",subtitle:"H2 blocker — prevents and treats heartburn and GERD",generics:["famotidine"],trades:["Pepcid"],drugClass:"H2-receptor antagonist",suffix:"Suffix: -TIDINE",mechanism:"H2-receptor antagonist. Blocks histamine at H2 receptors on gastric parietal cells → decreases stomach acid production. Less potent than PPIs but faster onset.",uses:["Prevention and treatment of heartburn","GERD","Peptic ulcers"],sideEffects:["Headache and dizziness","Mild constipation or diarrhea"],patientEd:["Take 20–40 mg PO once or twice daily","Can be taken before meals to prevent heartburn","Available OTC for short-term heartburn relief"],nursing:["Dose reduction required in severe kidney impairment","Less potent than PPIs but useful for mild to moderate acid suppression","Faster onset than PPIs — good for on-demand heartburn relief"],mnemonic:"-TIDINE = H2 blocker. Famo-TIDINE = Famously TIDES down acid. Not as strong as PPIs."},
{id:"gi3",cat:"Sick Call",title:"Omeprazole (Prilosec)",subtitle:"PPI — strongest acid suppressor — take 30–60 min BEFORE meals",generics:["omeprazole"],trades:["Prilosec"],drugClass:"Proton pump inhibitor (PPI)",suffix:"Suffix: -PRAZOLE",mechanism:"Proton Pump Inhibitor (PPI). Irreversibly blocks the H+/K+ ATPase (proton pump) of gastric parietal cells → stops the final step of acid secretion. Provides stronger, longer-lasting acid suppression than H2 blockers.",uses:["Frequent heartburn and GERD","Gastric and peptic ulcers","Prevention of NSAID-induced ulcers"],sideEffects:["Headache and abdominal pain","Long-term use: B12 deficiency, bone fractures, increased C. difficile risk"],patientEd:["Take 20–40 mg PO once daily, 30–60 MINUTES BEFORE the first meal of the day","Do not crush or chew delayed-release capsules","Not intended for long-term use without provider guidance"],nursing:["Concurrent use with clopidogrel (Plavix) reduces clopidogrel effectiveness — use famotidine instead","Monitor Mg, B12, and bone density with long-term use"],mnemonic:"-PRAZOLE = Proton pump inhibitor. Take 30 min BEFORE eating. Prilosec = PRIOR to meal."},
{id:"gi4",cat:"Sick Call",title:"Polyethylene Glycol (Miralax)",subtitle:"Osmotic laxative — gentle constipation relief — mix in any drink",generics:["polyethylene glycol 3350"],trades:["Miralax"],drugClass:"Osmotic laxative",suffix:"",mechanism:"Draws and retains water in the intestinal lumen by osmosis → softens stool and triggers bowel motility. Does not stimulate intestinal muscle contractions.",uses:["Occasional constipation","Chronic constipation management"],sideEffects:["Bloating and gas","Abdominal cramping","Diarrhea if dose is too high"],patientEd:["Dissolve 17 grams (one capful) in 8 oz of any beverage once daily","Can be mixed into water, juice, coffee, or any liquid — tasteless and odorless","May take 1–3 days to work — do not double dose"],nursing:["Contraindicated in: bowel obstruction, severe inflammatory bowel disease, or toxic megacolon","Does NOT cause dependency unlike stimulant laxatives","Monitor electrolytes with prolonged use in elderly"],mnemonic:"MIRALAX = 17g = one capful. OSMOSIS pulls water into stool. Gentle, no cramping."},
// ── SPECIFIC ANTIBIOTICS & ANTIVIRALS (from Antibiotics_Antivirals_Flashcards) ─
{id:"ab1",cat:"Sick Call",title:"Azithromycin (Z-Pak)",subtitle:"Macrolide antibiotic — Z-Pak regimen — PCN allergy alternative",generics:["azithromycin"],trades:["Zithromax","Z-Pak"],drugClass:"Macrolide antibiotic (bacteriostatic)",suffix:"Suffix: -MYCIN",mechanism:"Bacteriostatic. Binds to the 50S ribosomal subunit → inhibits bacterial protein synthesis → slows bacterial growth and reproduction.",uses:["Respiratory infections (pneumonia, bronchitis)","Strep throat for penicillin-allergic patients","Chlamydia (STI)"],sideEffects:["GI upset (nausea and diarrhea)","QT prolongation (arrhythmia risk — monitor ECG in high-risk patients)"],patientEd:["Z-Pak regimen: 500 mg PO on Day 1, then 250 mg daily on Days 2–5","For chlamydia: 1 gram PO as a single dose","Finish the entire course even if feeling better"],nursing:["Contraindicated in: history of QT prolongation or severe liver dysfunction","Monitor ECG (QT interval) in patients with cardiac history","Best alternative for penicillin-allergic patients with respiratory infections"],mnemonic:"AzithroMYCIN = Z-Pak. 5 days. Go-to antibiotic for PCN allergy + respiratory infections."},
{id:"ab2",cat:"Sick Call",title:"Amoxicillin (Amoxil)",subtitle:"Broad-spectrum penicillin — ear infections, strep, pneumonia",generics:["amoxicillin"],trades:["Amoxil","Trimox"],drugClass:"Beta-lactam antibiotic (aminopenicillin)",suffix:"Suffix: -CILLIN",mechanism:"Bactericidal. Binds to penicillin-binding proteins (PBPs) → inhibits bacterial cell wall synthesis → causes cell lysis and death. Broader spectrum than original penicillin.",uses:["Ear infections (otitis media)","Strep throat","Sinus infections","Simple community-acquired pneumonia"],sideEffects:["GI upset (nausea, diarrhea)","Rash (assess for true allergy vs. drug reaction)","Yeast infections (superinfection)"],patientEd:["Take 500–875 mg PO every 12 hours","Finish the ENTIRE course even if feeling better","Report any rash, hives, or breathing difficulty immediately"],nursing:["Contraindicated in: severe anaphylactic allergy to penicillins or cephalosporins","Ask about penicillin allergy BEFORE the first dose","Cross-sensitivity with cephalosporins (~1–2%)"],mnemonic:"AMOXicillin = -CILLIN = Cell Wall Killer. BACTERICIDAL. PCN allergy use Azithromycin."},
{id:"ab3",cat:"Sick Call",title:"Doxycycline (Vibramycin)",subtitle:"Tetracycline — MRSA skin, tick-borne illness — photosensitivity",generics:["doxycycline"],trades:["Vibramycin","Doryx"],drugClass:"Tetracycline antibiotic (bacteriostatic)",suffix:"Suffix: -CYCLINE",mechanism:"Bacteriostatic. Binds to the 30S ribosomal subunit → prevents bacterial protein synthesis → stops bacterial reproduction.",uses:["Skin infections with suspected MRSA","Tick-borne illnesses (Lyme disease, Rocky Mountain Spotted Fever)","Atypical pneumonia (Mycoplasma, Chlamydia)"],sideEffects:["Severe photosensitivity (sunburn risk — wear sunscreen)","Pill esophagitis if not taken with adequate water and staying upright","GI upset"],patientEd:["Take 100 mg PO every 12 hours","Take with a FULL glass of water and stay UPRIGHT for 30 minutes (prevents esophageal ulceration)","Wear sunscreen and avoid prolonged sun exposure","Avoid dairy, antacids, and iron within 2 hours of dose (reduces absorption)"],nursing:["Contraindicated in: pregnancy, breastfeeding, and children under 8 (permanent tooth discoloration and impaired bone growth)","Classic tick-borne illness treatment — go-to drug for Lyme disease and RMSF"],mnemonic:"-CYCLINE = Stay out of SUNSHINE! No kids under 8. Take with water and STAY UPRIGHT."},
{id:"ab4",cat:"Sick Call",title:"Trimethoprim-Sulfamethoxazole (Bactrim)",subtitle:"Sulfa antibiotic — UTIs and MRSA skin infections",generics:["trimethoprim-sulfamethoxazole"],trades:["Bactrim","Bactrim DS","Septra"],drugClass:"Sulfonamide antibiotic (bacteriostatic)",suffix:"Prefix: SULFA-",mechanism:"Bacteriostatic. Inhibits two sequential steps in bacterial folic acid synthesis → bacteria cannot produce DNA building blocks → stops bacterial reproduction.",uses:["Urinary tract infections (UTIs)","Skin and soft tissue infections (highly effective for community-acquired MRSA)","Pneumocystis jiroveci pneumonia (PCP) in immunocompromised patients"],sideEffects:["Photosensitivity (wear sunscreen)","Rash and GI upset","Hyperkalemia (elevated potassium)","Stevens-Johnson Syndrome (rare but severe skin reaction)"],patientEd:["Take 1 DS (double-strength: 800/160 mg) tablet PO every 12 hours","Drink plenty of water to prevent crystalluria","Report any rash or skin blistering immediately (may be SJS)"],nursing:["Contraindicated in: sulfa allergy, late pregnancy, and severe renal disease","Cross-sensitivity with thiazide diuretics, furosemide, and sulfonylureas","First-line outpatient treatment for community-acquired MRSA skin infections"],mnemonic:"BACTRIM = SULFA prefix. Bacteria cannot make folic acid and die. Sunscreen + Hydrate."},
{id:"ab5",cat:"Sick Call",title:"Ciprofloxacin (Cipro)",subtitle:"Fluoroquinolone — UTIs, traveler's diarrhea — tendon rupture risk",generics:["ciprofloxacin"],trades:["Cipro"],drugClass:"Fluoroquinolone antibiotic (bactericidal)",suffix:"Suffix: -FLOXACIN",mechanism:"Bactericidal. Inhibits bacterial DNA gyrase and topoisomerase IV → prevents bacterial DNA from replicating → bacterial cell death.",uses:["Severe urinary tract infections (UTIs)","Traveler's diarrhea and infectious diarrhea","Respiratory infections (anthrax prophylaxis)"],sideEffects:["GI upset and dizziness","Photosensitivity","Tendon rupture (especially Achilles) — BLACK BOX WARNING","QT prolongation"],patientEd:["Take 500 mg PO every 12 hours","Do NOT take with milk, antacids, or iron supplements (reduces absorption by up to 90%)","Report tendon pain IMMEDIATELY — stop activity and call provider","Wear sunscreen"],nursing:["Contraindicated in: myasthenia gravis and pregnancy","BLACK BOX WARNING: tendon rupture risk — highest in patients over 60, on corticosteroids, or with organ transplants","Monitor QT interval in cardiac patients"],mnemonic:"-FLOXACIN = FLOXed tendons! QT + Tendon rupture. Do NOT take with dairy, antacids, or iron."},
{id:"ab6",cat:"Sick Call",title:"Metronidazole (Flagyl)",subtitle:"Antibiotic and antiprotozoal — NEVER mix with alcohol",generics:["metronidazole"],trades:["Flagyl"],drugClass:"Nitroimidazole antibiotic / Antiprotozoal",suffix:"",mechanism:"Bactericidal against anaerobes. Disrupts DNA and inhibits nucleic acid synthesis in susceptible microorganisms → prevents bacterial and protozoal replication and cell death.",uses:["Bacterial vaginosis","Trichomonas (STI)","Giardia and C. difficile","Anaerobic and mixed infections"],sideEffects:["Metallic taste in mouth (very common — classic side effect)","Dark urine (harmless)","GI upset and nausea"],patientEd:["Take 500 mg PO every 8–12 hours","ABSOLUTELY NO ALCOHOL during treatment and for 3 days after the last dose (severe vomiting — disulfiram-like reaction)","Expect a metallic taste — this is normal","Urine may turn dark — harmless"],nursing:["Absolute contraindication: NO ALCOHOL — disulfiram-like reaction causes severe nausea, vomiting, flushing","Contraindicated in first trimester of pregnancy","Monitor for peripheral neuropathy with prolonged use"],mnemonic:"FLAGYL + ALCOHOL = SEVERE reaction. METALLIC taste = classic. 3 DAYS no alcohol after stopping."},
{id:"ab7",cat:"Sick Call",title:"Clindamycin (Cleocin)",subtitle:"Lincosamide antibiotic — skin and dental infections — HIGHEST C. diff risk",generics:["clindamycin"],trades:["Cleocin"],drugClass:"Lincosamide antibiotic (bacteriostatic)",suffix:"",mechanism:"Bacteriostatic. Binds to the 50S ribosomal subunit → inhibits bacterial protein synthesis → stops bacterial growth. Excellent anaerobic and gram-positive coverage. Highest C. diff risk of any antibiotic class.",uses:["Skin and soft tissue infections","Dental infections (prophylaxis for PCN-allergic patients)","Anaerobic infections","Patients with severe penicillin allergies"],sideEffects:["C. difficile colitis (highest risk of any antibiotic) — severe watery diarrhea — BLACK BOX WARNING","General GI upset"],patientEd:["Take 300–450 mg PO every 6–8 hours","Report IMMEDIATELY: severe, watery, or bloody diarrhea — could be C. diff","Complete the full antibiotic course"],nursing:["BLACK BOX WARNING: HIGHEST C. diff association of all antibiotic classes","Contraindicated in: history of pseudomembranous colitis or regional enteritis","STOP medication immediately if severe diarrhea develops and test for C. diff"],mnemonic:"CLINDAmycin = C.diff LINDA knocking. HIGHEST C.diff risk. STOP if watery or bloody diarrhea."},
{id:"ab8",cat:"Sick Call",title:"Acyclovir (Zovirax)",subtitle:"Antiviral — HSV and Shingles — manages outbreaks — does NOT cure",generics:["acyclovir"],trades:["Zovirax"],drugClass:"Antiviral (nucleoside analogue)",suffix:"Suffix: -VIR",mechanism:"Inhibits viral DNA polymerase → stops viral DNA replication inside infected cells. Activated by viral thymidine kinase (selective to infected cells). Does NOT cure the herpes virus — it suppresses and manages outbreaks.",uses:["Herpes Simplex Virus (HSV-1 and HSV-2)","Varicella-Zoster (Shingles and Chickenpox)"],sideEffects:["Headache and nausea","Acute kidney injury if patient is dehydrated (especially IV form)"],patientEd:["HSV dose: 400 mg PO 3 times daily","Shingles dose: 800 mg PO 5 times daily for 7–10 days","Start treatment ASAP at first sign of outbreak — most effective within 72 hours","Does NOT cure the virus — manages and suppresses outbreaks. Stay well hydrated"],nursing:["Contraindicated in: severe renal failure (requires dose adjustment) and severe dehydration","Adequate hydration is critical to prevent nephrotoxicity (especially IV acyclovir)"],mnemonic:"Acyclo-VIR = -VIR suffix = anti-VIRal. DOES NOT CURE herpes. Manages outbreaks. STAY HYDRATED."},
{id:"ab9",cat:"Sick Call",title:"Cephalexin (Keflex)",subtitle:"1st-gen cephalosporin — skin infections — PCN cross-sensitivity",generics:["cephalexin"],trades:["Keflex"],drugClass:"First-generation cephalosporin (beta-lactam antibiotic)",suffix:"Prefix: CEF-/CEPH-",mechanism:"Bactericidal. Inhibits bacterial cell wall synthesis by binding to penicillin-binding proteins → disrupts peptidoglycan cross-linking → bacterial cell lysis and death.",uses:["Uncomplicated skin infections (cellulitis, impetigo)","Simple UTIs","Strep throat (alternative to amoxicillin)"],sideEffects:["GI upset and diarrhea","Mild rash"],patientEd:["Take 500 mg PO every 6–12 hours","Take with food if GI upset occurs","Finish the ENTIRE course of antibiotics","Report rash or signs of allergic reaction"],nursing:["Contraindicated in: severe anaphylactic allergy to penicillins (1–2% cross-reactivity risk)","Ask about penicillin allergy BEFORE administering","Good choice for uncomplicated skin infections in the outpatient or field setting"],mnemonic:"CEPHalexin = CEF prefix = Cell wall Enemy Fighter. KEFLEX. 1–2% cross-reactivity with PCN."},
// ── SICK CALL · TRIAGE CRITERIA & RED FLAGS (clinical reference cards) ──
{id:"sc-ottawa-ankle",cat:"Sick Call",title:"Ottawa Ankle Rules",subtitle:"When does an ankle injury require an X-ray?",clinical:true,intro:"X-ray is required if there is pain in the malleolar zone AND any one of the following:",groups:[{label:"X-ray Required If Any Present",items:["Bone tenderness at the posterior edge or tip of the lateral malleolus (distal 6 cm)","Bone tenderness at the posterior edge or tip of the medial malleolus (distal 6 cm)","Inability to bear weight (4 steps) both immediately after injury and in the clinic"]}],note:"Swelling, bruising, or a positive inversion stress test alone do NOT meet criteria for X-ray.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-ottawa-foot",cat:"Sick Call",title:"Ottawa Foot Rules",subtitle:"When does midfoot pain require an X-ray?",clinical:true,intro:"X-ray is required if there is pain in the midfoot zone AND any one of the following:",groups:[{label:"X-ray Required If Any Present",items:["Bone tenderness at the base of the 5th metatarsal","Bone tenderness at the navicular bone","Inability to bear weight (4 steps) both immediately after injury and in the clinic"]}],note:"Generalized arch pain or dorsal swelling alone do NOT meet criteria for X-ray.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-ottawa-knee",cat:"Sick Call",title:"Ottawa Knee Rules",subtitle:"When does a knee injury require an X-ray?",clinical:true,intro:"X-ray is required after a knee injury if any one of the following is present:",groups:[{label:"X-ray Required If Any Present",items:["Age 55 or older","Isolated tenderness of the patella","Tenderness at the head of the fibula","Inability to flex the knee to 90 degrees","Inability to bear weight (4 steps) immediately and in the clinic"]}],note:"Effusion/swelling or a positive McMurray's test alone do NOT meet criteria for X-ray.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-htn-redflags",cat:"Sick Call",title:"Hypertensive Emergency Red Flags",subtitle:"Signs of end-organ damage requiring emergent referral",clinical:true,intro:"A markedly elevated blood pressure WITH any of these red flags signals a hypertensive emergency (end-organ damage), not simple urgency:",groups:[{label:"Neurological",items:["Severe headache","Altered mental status","Dizziness","Weakness"]},{label:"Cardiopulmonary",items:["Dyspnea","Chest pain","Palpitations"]},{label:"Other",items:["Blurry vision","Severe epistaxis","Hematuria"]}],note:"Mild symptoms (mild headache, a few droplets of epistaxis, mild tachycardia, fatigue, tremor) are NOT emergency red flags.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-cauda-equina",cat:"Sick Call",title:"Back Pain — Cauda Equina Red Flags",subtitle:"Findings requiring EMERGENCY referral",clinical:true,intro:"Cauda equina syndrome is a surgical emergency. Refer immediately if any of these are present:",groups:[{label:"Emergency Red Flags",items:["Saddle anesthesia","Fecal incontinence","Urinary incontinence (or retention)","Severe bilateral leg weakness"]}],note:"Unilateral leg weakness or pain triggered by activity alone are less specific and do not by themselves indicate cauda equina.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-back-systemic",cat:"Sick Call",title:"Back Pain — Systemic Red Flags",subtitle:"Findings requiring further workup",clinical:true,intro:"These systemic red flags suggest a serious underlying cause (infection, malignancy) and warrant further workup:",groups:[{label:"Systemic Red Flags",items:["History of cancer","Unexplained weight loss","Fever","Night pain"]}],note:"Pain worse with exercise or a recent heavy-lifting episode point toward mechanical (non-emergent) back pain.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-surgical-abdomen",cat:"Sick Call",title:"Surgical Abdomen — Key Signs",subtitle:"Appendicitis, cholecystitis & peritonitis findings",clinical:true,intro:"Classic exam findings that point toward a surgical abdomen:",groups:[{label:"Appendicitis",items:["McBurney's Point tenderness (RLQ)","Rovsing's sign","Right lower quadrant pain"]},{label:"Cholecystitis",items:["Murphy's sign positive","Right upper quadrant pain/tenderness","Fever"]},{label:"Peritonitis",items:["Rebound tenderness","Abdominal rigidity","Severe acute abdominal pain"]}],note:"Localized point tenderness only or mild diffuse discomfort are NOT signs of peritonitis.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-centor",cat:"Sick Call",title:"Modified Centor Score (Strep Criteria)",subtitle:"Screening for strep pharyngitis",clinical:true,intro:"Add 1 point for each criterion present (4 points possible):",groups:[{label:"1 Point Each",items:["Absence of cough","Swollen, tender anterior cervical nodes","Temperature > 100.4°F (38°C)","Tonsillar exudate or swelling"]}],note:"Interpretation: Score 0–1 = low risk, likely viral. Score 2–3 = perform Rapid Strep Test. Score 4 = high risk, treat or test.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""},
{id:"sc-lymph-nodes",cat:"Sick Call",title:"Lymph Nodes — Locations & Associations",subtitle:"Which nodes drain which infections",clinical:true,intro:"The four nodes typically checked in a patient with cold/flu symptoms — and what each is associated with:",groups:[{label:"Node → Association",items:["Anterior cervical (front of neck) → Strep pharyngitis and URIs","Posterior cervical (back of neck) → Epstein-Barr Virus (Mono)","Submandibular (along the jawline) → oral/dental infections and Strep","Submental (just behind the tip of the chin) → lower lip, floor-of-mouth, and dental infections"]}],note:"Axillary and inguinal nodes are not part of the routine cold/flu HEENT node check.",generics:[],trades:[],uses:[],sideEffects:[],patientEd:[],nursing:[],mechanism:"",drugClass:"",suffix:"",mnemonic:""}
];

