// ── PHARMACOLOGY QUIZ QUESTIONS ─────────────────────────────────────────────
const PHARMA_QUIZ = [
{cat:"CNS",q:"What is the maximum recommended daily dose of Acetaminophen (Tylenol) for a healthy adult?",opts:["500 mg","2,000 mg","3,000 mg","4,000 mg"],correct:"4,000 mg",explain:"The max daily dose of acetaminophen for a healthy adult is 4,000 mg. In elderly patients or those with liver disease, the limit is 3,000 mg/day.",sc:1},
{cat:"CNS",q:"What is the maximum single oral dose of Acetaminophen for an adult?",opts:["500 mg","650 mg","750 mg","1,000 mg"],correct:"1,000 mg",explain:"The maximum single oral dose of acetaminophen is 1,000 mg. Individual doses greater than this significantly increase hepatotoxicity risk.",sc:1},
{cat:"CNS",q:"What is the maximum recommended daily dose of Ibuprofen (Advil/Motrin) for an adult?",opts:["1,200 mg","2,400 mg","3,200 mg","4,000 mg"],correct:"3,200 mg",explain:"The maximum daily OTC dose of ibuprofen is 1,200 mg, but under medical supervision the maximum is 3,200 mg/day. Always take with food.",sc:1},
{cat:"CNS",q:"What is the recommended single oral dose range for Ibuprofen?",opts:["100–200 mg","400–800 mg","1,000–1,200 mg","200–600 mg"],correct:"400–800 mg",explain:"The standard single dose of ibuprofen for pain or fever is 400–800 mg. Lower doses (200–400 mg) are used for mild pain; 600–800 mg for moderate pain or inflammation.",sc:1},
{cat:"CNS",q:"What is the standard intramuscular (IM) dose of Ketorolac (Toradol)?",opts:["10 mg","15 mg","30 mg","60 mg"],correct:"30 mg",explain:"The standard IM dose of Ketorolac (Toradol) is 30 mg. It is one of the most powerful non-narcotic analgesics available and must not be used for more than 5 days.",sc:1},
{cat:"CNS",q:"What is the maximum duration of use for Ketorolac (Toradol) across all routes combined?",opts:["3 days","5 days","7 days","10 days"],correct:"5 days",explain:"Ketorolac must NEVER be used for more than 5 days across all routes combined (IV + IM + PO). Prolonged use causes serious GI bleeding and renal damage.",sc:1},
{cat:"CNS",q:"What is the maximum recommended daily dose of Naproxen Sodium (Aleve)?",opts:["440–500 mg","1,000–1,250 mg","1,500 mg","2,000 mg"],correct:"1,000–1,250 mg",explain:"The maximum daily dose of naproxen sodium is 1,000–1,250 mg. It is dosed every 12 hours due to its longer half-life compared to ibuprofen.",sc:1},
{cat:"CNS",q:"What is the standard single oral dose range for Naproxen Sodium?",opts:["100–200 mg","220–500 mg","600–800 mg","1,000 mg"],correct:"220–500 mg",explain:"The standard single dose of naproxen sodium is 220–500 mg taken every 12 hours. The 220 mg OTC dose is for mild pain; higher doses are used for inflammation.",sc:1},
{cat:"CNS",q:"What is the recommended single oral dose range for Aspirin for pain or fever in adults?",opts:["81 mg only","325–1,000 mg","1,500 mg","2,000 mg"],correct:"325–1,000 mg",explain:"For pain or fever, aspirin is given as 325–1,000 mg. The 81 mg low dose is for cardiovascular protection (antiplatelet), not for analgesia.",sc:1},
{cat:"CNS",q:"What is the recommended dose of Aspirin for a patient with a suspected acute MI?",opts:["81 mg swallowed whole","162–324 mg chewed","500 mg swallowed","1,000 mg swallowed"],correct:"162–324 mg chewed",explain:"For suspected acute MI, 162–324 mg of aspirin should be CHEWED (not swallowed whole) for rapid absorption. Chewing allows faster platelet inhibition.",sc:1},
{cat:"CNS",q:"What is the standard application dose for Diclofenac 1% Gel (Voltaren)?",opts:["1 gram once daily","2–4 grams up to 4 times daily","5 grams twice daily","10 grams once daily"],correct:"2–4 grams up to 4 times daily",explain:"Diclofenac 1% gel is applied 2–4 grams up to 4 times daily to the affected joint. This topical route minimizes systemic absorption and GI risk.",sc:1},
{cat:"CNS",q:"A patient has acute, severe lower back pain and cannot take opioids. Which non-narcotic option provides the most powerful analgesic effect?",opts:["Ibuprofen 800 mg PO","Acetaminophen 1,000 mg PO","Ketorolac (Toradol) 30 mg IM","Diclofenac gel applied topically"],correct:"Ketorolac (Toradol) 30 mg IM",explain:"Ketorolac (Toradol) IM is the most powerful non-narcotic analgesic available, approaching opioid-level pain relief. It is ideal for acute severe pain when opioids must be avoided.",sc:1},
{cat:"CNS",q:"A patient with a history of active GI bleeding needs pain relief for knee pain. Which is the SAFEST option?",opts:["Ibuprofen 600 mg PO","Diclofenac 1% Gel applied topically to the knee","Naproxen 500 mg PO","High-dose Aspirin 1,000 mg PO"],correct:"Diclofenac 1% Gel applied topically to the knee",explain:"Diclofenac 1% gel has minimal systemic absorption, making it the safest NSAID option for patients with GI bleeding history. Oral NSAIDs are contraindicated in active GI bleeding.",sc:1},
{cat:"CNS",q:"Which patient is most likely contraindicated for Aspirin therapy?",opts:["An elderly adult with hypertension","A child with chickenpox who has a fever","An adult with rheumatoid arthritis","An adult with stable angina"],correct:"A child with chickenpox who has a fever",explain:"Aspirin is absolutely CONTRAINDICATED in children and teenagers with viral illnesses (chickenpox, influenza) due to the risk of Reye's syndrome — a rare but life-threatening condition causing brain and liver damage.",sc:1},
{cat:"CNS",q:"What is the mechanism of action of Acetaminophen?",opts:["Inhibits COX-1 and COX-2 peripherally causing anti-inflammatory effects","Blocks prostaglandin synthesis in the periphery to reduce inflammation","Works centrally in the brain to elevate the pain threshold and regulate body temperature","Inhibits platelet aggregation by blocking thromboxane A2"],correct:"Works centrally in the brain to elevate the pain threshold and regulate body temperature",explain:"Acetaminophen works CENTRALLY in the brain — it raises the pain threshold and acts on the hypothalamus to lower fever. It does NOT have significant peripheral anti-inflammatory or antiplatelet effects.",sc:1},
{cat:"CNS",q:"How often is Naproxen Sodium (Aleve) typically dosed compared to Ibuprofen?",opts:["Every 4–6 hours, same as ibuprofen","Every 8 hours, more frequently than ibuprofen","Every 12 hours, less frequently than ibuprofen","Once daily, less frequently than ibuprofen"],correct:"Every 12 hours, less frequently than ibuprofen",explain:"Naproxen sodium has a longer half-life than ibuprofen and is dosed every 12 hours. Ibuprofen is dosed every 4–6 hours. This is a key pharmacokinetic difference between the two drugs.",sc:1},
// ── DECONGESTANTS & ANTIHISTAMINES ──
{cat:"Respiratory",q:"What is the standard single oral dose range for Pseudoephedrine (Sudafed)?",opts:["10–15 mg","30–60 mg","100–120 mg","150–200 mg"],correct:"30–60 mg",explain:"The standard oral dose of pseudoephedrine is 30–60 mg every 4–6 hours. The max 24-hour dose is 240 mg.",sc:1},
{cat:"Respiratory",q:"What is the maximum recommended 24-hour dose of Pseudoephedrine?",opts:["120 mg","180 mg","240 mg","360 mg"],correct:"240 mg",explain:"The maximum 24-hour dose of pseudoephedrine is 240 mg. Exceeding this increases the risk of cardiovascular side effects like hypertension, tachycardia, and arrhythmias.",sc:1},
{cat:"Respiratory",q:"What is the standard dose of Oxymetazoline (Afrin) nasal spray?",opts:["1 spray in one nostril once daily","2–3 sprays in each nostril every 10–12 hours","4–5 sprays in each nostril every 6 hours","1 spray in each nostril every 24 hours"],correct:"2–3 sprays in each nostril every 10–12 hours",explain:"Oxymetazoline (Afrin) is dosed as 2–3 sprays in each nostril every 10–12 hours. It should NEVER be used for more than 3–5 days to prevent rebound congestion.",sc:1},
{cat:"Respiratory",q:"What is the maximum duration of use for Oxymetazoline (Afrin) nasal spray?",opts:["1–2 days","3–5 days","7–10 days","14 days"],correct:"3–5 days",explain:"Oxymetazoline must not be used for more than 3–5 days. Extended use causes rhinitis medicamentosa — rebound congestion that is worse than the original symptoms.",sc:1},
{cat:"Respiratory",q:"What is the standard single dose of Diphenhydramine (Benadryl) for an adult?",opts:["5–10 mg","12.5 mg","25–50 mg","75–100 mg"],correct:"25–50 mg",explain:"The standard adult dose of diphenhydramine is 25–50 mg every 4–6 hours. It is a 1st-generation antihistamine that readily crosses the blood-brain barrier, causing significant sedation.",sc:1},
{cat:"Respiratory",q:"What is the standard daily dose of Loratadine (Claritin) for an adult?",opts:["5 mg twice daily","10 mg once daily","20 mg once daily","5 mg once daily"],correct:"10 mg once daily",explain:"Loratadine (Claritin) is dosed as 10 mg once daily. It is a 2nd-generation antihistamine that does not readily cross the blood-brain barrier, making it non-sedating.",sc:1},
{cat:"Respiratory",q:"What is the standard daily dose of Cetirizine (Zyrtec) for an adult?",opts:["5 mg twice daily","10 mg once daily","20 mg once daily","5 mg once daily"],correct:"10 mg once daily",explain:"Cetirizine (Zyrtec) is dosed as 10 mg once daily. It is a 2nd-generation antihistamine but has a slightly higher risk of mild sedation compared to loratadine.",sc:1},
{cat:"Respiratory",q:"What is the standard single immediate-release dose of Guaifenesin (Mucinex)?",opts:["100 mg","200–400 mg","600–1,200 mg","1,600 mg"],correct:"200–400 mg",explain:"The standard single dose of immediate-release guaifenesin is 200–400 mg every 4 hours. Extended-release tablets are dosed at 600–1,200 mg every 12 hours.",sc:1},
{cat:"Respiratory",q:"Why does Diphenhydramine (Benadryl) cause sedation while Loratadine (Claritin) does not?",opts:["Benadryl has a longer half-life than Claritin","Benadryl is dosed higher than Claritin","Benadryl readily crosses the blood-brain barrier while Claritin does not","Benadryl blocks more H1 receptors than Claritin"],correct:"Benadryl readily crosses the blood-brain barrier while Claritin does not",explain:"1st-generation antihistamines like diphenhydramine readily cross the blood-brain barrier, blocking histamine receptors in the CNS and causing sedation. 2nd-generation antihistamines like loratadine are designed to stay peripheral.",sc:1},
{cat:"Respiratory",q:"Which antihistamine is the BEST choice as an adjunct treatment for anaphylaxis?",opts:["Loratadine (Claritin) — non-sedating and fast-acting","Cetirizine (Zyrtec) — less sedating and effective","Diphenhydramine (Benadryl) — most effective for acute allergic reactions","Guaifenesin (Mucinex) — helps with respiratory symptoms"],correct:"Diphenhydramine (Benadryl) — most effective for acute allergic reactions",explain:"Diphenhydramine (Benadryl) is the antihistamine of choice as an adjunct to epinephrine in anaphylaxis. The 1st-generation agents have a faster onset for acute allergic reactions. Remember: epinephrine is ALWAYS given first.",sc:1},
{cat:"Respiratory",q:"A soldier needs an antihistamine for seasonal allergies but will be operating heavy machinery. Which is the BEST choice?",opts:["Diphenhydramine (Benadryl) — most effective antihistamine","Loratadine (Claritin) — non-sedating antihistamine","Promethazine (Phenergan) — strong antihistamine with sedation","Hydroxyzine (Vistaril) — good for allergies"],correct:"Loratadine (Claritin) — non-sedating antihistamine",explain:"Loratadine (Claritin) is the best choice when the patient must remain alert. It is a 2nd-generation antihistamine that does not cross the blood-brain barrier and does not cause significant sedation.",sc:1},
{cat:"Respiratory",q:"What is the primary mechanism of action of Oxymetazoline?",opts:["Beta-2 agonist causing bronchodilation","Antihistamine blocking H1 receptors in nasal tissue","Direct-acting alpha-adrenergic agonist causing intense, localized vasoconstriction of nasal blood vessels","Inhibits leukotriene synthesis to reduce nasal inflammation"],correct:"Direct-acting alpha-adrenergic agonist causing intense, localized vasoconstriction of nasal blood vessels",explain:"Oxymetazoline works as a direct-acting alpha-adrenergic agonist. It constricts the blood vessels in the nasal mucosa, rapidly reducing nasal congestion within minutes of application.",sc:1},
{cat:"Respiratory",q:"What is the most common complaint when a patient takes Pseudoephedrine (Sudafed)?",opts:["Drowsiness and fatigue","Dry mouth and constipation","Jitteriness, anxiety, and increased heart rate","Nausea and vomiting"],correct:"Jitteriness, anxiety, and increased heart rate",explain:"Pseudoephedrine's sympathomimetic effects most commonly cause jitteriness, anxiety, and increased heart rate. This is why it is contraindicated in patients with hypertension, heart disease, and hyperthyroidism.",sc:1},
{cat:"Respiratory",q:"What key patient education should ALWAYS be given with Guaifenesin (Mucinex)?",opts:["Take on an empty stomach for best absorption","You MUST drink adequate fluids (water) for this medication to effectively thin your mucus","Avoid dairy products while taking this medication","Take at bedtime only — causes significant daytime sedation"],correct:"You MUST drink adequate fluids (water) for this medication to effectively thin your mucus",explain:"Guaifenesin is an expectorant that works by thinning mucus secretions. Without adequate hydration, it cannot effectively liquefy the mucus. Patients must drink at least 2 liters of fluid daily.",sc:1},
// ── GI MEDICATIONS ──
{cat:"GI",q:"What is the standard single dose of Bismuth Subsalicylate (Pepto-Bismol)?",opts:["100 mg (1 tablet or 5 mL)","262 mg (1 tablet or 15 mL)","524 mg (2 tablets or 30 mL)","1,048 mg (4 tablets or 60 mL)"],correct:"524 mg (2 tablets or 30 mL)",explain:"The standard single dose of Bismuth Subsalicylate (Pepto-Bismol) is 524 mg, which equals 2 regular-strength tablets or 30 mL of liquid. Max is 8 doses in 24 hours.",sc:1},
{cat:"GI",q:"What is the maximum number of Bismuth Subsalicylate (Pepto-Bismol) doses allowed in a 24-hour period?",opts:["4 doses","6 doses","8 doses","12 doses"],correct:"8 doses",explain:"Bismuth Subsalicylate may be taken up to 8 doses in a 24-hour period. Exceeding this risks salicylate toxicity — symptoms include tinnitus (ringing in the ears).",sc:1},
{cat:"GI",q:"What is the standard initial dose of Loperamide (Imodium) for acute diarrhea?",opts:["1 mg","2 mg","4 mg","8 mg"],correct:"4 mg",explain:"The standard initial dose of loperamide is 4 mg (2 caplets), followed by 2 mg after each loose stool. The maximum OTC dose is 8 mg per day without medical supervision.",sc:1},
{cat:"GI",q:"What is the maximum OTC daily dose of Loperamide (Imodium)?",opts:["4 mg per day","8 mg per day","16 mg per day","24 mg per day"],correct:"8 mg per day",explain:"The maximum OTC dose of loperamide is 8 mg per day for self-treatment of acute diarrhea. Under medical supervision, up to 16 mg per day may be used for chronic diarrhea.",sc:1},
{cat:"GI",q:"What is the standard dose of Famotidine (Pepcid)?",opts:["5–10 mg twice daily","20–40 mg once or twice daily","80–160 mg once daily","5 mg once daily"],correct:"20–40 mg once or twice daily",explain:"Famotidine (Pepcid) is typically dosed at 20–40 mg once or twice daily. It is an H2 receptor antagonist — less potent than PPIs but effective for mild to moderate acid suppression.",sc:1},
{cat:"GI",q:"What is the standard dose of Omeprazole (Prilosec)?",opts:["5–10 mg once daily","20–40 mg once daily","80 mg twice daily","5 mg twice daily"],correct:"20–40 mg once daily",explain:"Omeprazole is typically dosed at 20–40 mg once daily. It is a proton pump inhibitor (PPI) — the most potent class of acid suppressors. It must be taken 30–60 minutes BEFORE a meal.",sc:1},
{cat:"GI",q:"What is the standard single dose of Docusate Sodium (Colace)?",opts:["25 mg","50 mg","100 mg","200 mg"],correct:"100 mg",explain:"The standard single dose of Docusate Sodium (Colace) is 100 mg, typically taken once or twice daily. It is a stool softener, not a laxative — it allows water and fat to penetrate the stool.",sc:1},
{cat:"GI",q:"What is the standard single dose of Polyethylene Glycol 3350 (Miralax)?",opts:["8.5 grams (half capful)","17 grams (one capful)","34 grams (two capfuls)","51 grams (three capfuls)"],correct:"17 grams (one capful)",explain:"The standard dose of Miralax is 17 grams (one capful) dissolved in 4–8 oz of any beverage, taken once daily. It is a gentle osmotic laxative that typically works within 1–3 days.",sc:1},
{cat:"GI",q:"What is the standard single dose of Ondansetron (Zofran) for nausea and vomiting?",opts:["1–2 mg","4–8 mg","10–12 mg","16–24 mg"],correct:"4–8 mg",explain:"Ondansetron is typically dosed at 4–8 mg. It is a 5-HT3 serotonin antagonist — considered the gold standard antiemetic for post-operative and chemotherapy-induced nausea.",sc:1},
{cat:"GI",q:"A patient is vomiting after surgery. Which antiemetic is the BEST choice?",opts:["Bismuth Subsalicylate (Pepto-Bismol) — coats the stomach","Loperamide (Imodium) — slows GI motility","Ondansetron (Zofran) — serotonin antagonist, gold standard for PONV","Omeprazole (Prilosec) — reduces stomach acid"],correct:"Ondansetron (Zofran) — serotonin antagonist, gold standard for PONV",explain:"Ondansetron (Zofran) is the gold standard for post-operative nausea and vomiting (PONV) and chemotherapy-induced nausea. It blocks 5-HT3 serotonin receptors in the GI tract and brain."},
{cat:"GI",q:"What important side effect should a patient ALWAYS be warned about before taking Bismuth Subsalicylate (Pepto-Bismol)?",opts:["Their urine will turn bright orange","Their skin may become temporarily yellow","Their tongue and stool may turn black — this is harmless","Their saliva will turn gray"],correct:"Their tongue and stool may turn black — this is harmless",explain:"Bismuth reacts with trace sulfur in saliva and stool to form bismuth sulfide — a black compound. This harmless discoloration alarms patients if they are not warned in advance.",sc:1},
{cat:"GI",q:"Loperamide (Imodium) is CONTRAINDICATED in which situation?",opts:["Mild traveler's diarrhea without fever","Irritable bowel syndrome with diarrhea","Dysentery (bloody diarrhea) or suspected C. difficile infection","Post-ileostomy to reduce output"],correct:"Dysentery (bloody diarrhea) or suspected C. difficile infection",explain:"Loperamide must NOT be used when the diarrhea is caused by an infectious organism that needs to be expelled (like C. diff or bacteria causing dysentery). It can worsen the infection by keeping toxins in the bowel.",sc:1},
{cat:"GI",q:"When should Omeprazole (Prilosec) be taken for maximum effectiveness?",opts:["30–60 minutes before the first meal of the day","Immediately after eating a meal","At bedtime on an empty stomach","With a full glass of milk"],correct:"30–60 minutes before the first meal of the day",explain:"PPIs like omeprazole must be taken 30–60 minutes BEFORE the first meal. They block proton pumps that are activated by eating. Timing is critical — taking them AFTER a meal significantly reduces effectiveness.",sc:1},
{cat:"GI",q:"What is the mechanism of action of Famotidine (Pepcid)?",opts:["Irreversibly blocks the proton pump on parietal cells","Coats the stomach lining to form a protective barrier","H2-receptor antagonist that blocks histamine on gastric parietal cells, reducing acid production","Neutralizes hydrochloric acid in the stomach immediately"],correct:"H2-receptor antagonist that blocks histamine on gastric parietal cells, reducing acid production",explain:"Famotidine is an H2-receptor antagonist. It blocks histamine H2 receptors on gastric parietal cells, reducing acid secretion. It is less potent than PPIs but acts faster.",sc:1},
{cat:"GI",q:"Which is an important rule about timing when a patient takes Antacids?",opts:["Take antacids within 30 minutes of all other medications","Do not take antacids within 1–2 hours of other medications — they interfere with absorption","Take antacids at the exact same time as other medications for convenience","Antacids have no interaction with other medications"],correct:"Do not take antacids within 1–2 hours of other medications — they interfere with absorption",explain:"Antacids raise the gastric pH, which alters the absorption of many medications. Patients should be told to take antacids 1–2 hours apart from other drugs.",sc:1},
{cat:"GI",q:"Which medication is classified as an osmotic laxative?",opts:["Docusate Sodium (Colace) — stool softener","Polyethylene Glycol (Miralax) — osmotic laxative","Loperamide (Imodium) — antidiarrheal","Ondansetron (Zofran) — antiemetic"],correct:"Polyethylene Glycol (Miralax) — osmotic laxative",explain:"Polyethylene Glycol (Miralax) is an osmotic laxative. It draws water into the colon through osmosis to soften stool. Docusate is a stool softener; it does not draw water osmotically.",sc:1},
// ── ANTIBIOTICS & ANTIVIRALS ──
{cat:"Immune",q:"A patient has a confirmed Penicillin allergy and needs treatment for strep throat. What is the best alternative antibiotic?",opts:["Amoxicillin — a broader penicillin","Cephalexin — a cephalosporin","Azithromycin — a macrolide antibiotic","Ciprofloxacin — a fluoroquinolone"],correct:"Azithromycin — a macrolide antibiotic",explain:"When a patient has a penicillin allergy, Azithromycin (Zithromax) is the preferred alternative for strep throat. It belongs to the macrolide class and has no cross-reactivity with penicillin.",sc:1},
{cat:"Immune",q:"What is the most critical patient education point when taking Doxycycline?",opts:["Take on an empty stomach for best absorption","Take with a full glass of water and stay upright for at least 30 minutes","Take with a full glass of milk to prevent GI upset","Take at bedtime to minimize side effects"],correct:"Take with a full glass of water and stay upright for at least 30 minutes",explain:"Doxycycline can cause severe esophageal ulceration if it remains in contact with the esophagus. Patients must take it with a full glass of water and stay upright for 30 minutes.",sc:1},
{cat:"Immune",q:"Why is Doxycycline contraindicated in children under 8 and in pregnant women?",opts:["It crosses the placenta and causes birth defects in the heart","It causes permanent tooth discoloration and impaired bone growth in developing tissues","It causes severe liver toxicity in children","It causes irreversible kidney damage in fetuses"],correct:"It causes permanent tooth discoloration and impaired bone growth in developing tissues",explain:"Tetracyclines including doxycycline bind to calcium in developing teeth and bones, causing permanent yellow-gray discoloration of teeth and inhibiting bone growth. This is an absolute contraindication.",sc:1},
{cat:"Immune",q:"Which antibiotic is effective for MRSA infections in outpatient settings?",opts:["Amoxicillin — a broad-spectrum penicillin","Ciprofloxacin — a fluoroquinolone","Trimethoprim-Sulfamethoxazole (Bactrim) — covers community-acquired MRSA","Doxycycline alone — a tetracycline"],correct:"Trimethoprim-Sulfamethoxazole (Bactrim) — covers community-acquired MRSA",explain:"TMP-SMX (Bactrim) is one of the most common outpatient treatments for community-acquired MRSA (CA-MRSA) skin infections. It is a sulfonamide antibiotic that inhibits folic acid synthesis."},
{cat:"Immune",q:"What is the absolute contraindication that must ALWAYS be discussed with patients taking Metronidazole (Flagyl)?",opts:["Avoid all dairy products during treatment","Do not take with any other antibiotics","Consumption of alcohol during treatment and for 3 days after the last dose","Avoid exposure to sunlight while on this medication"],correct:"Consumption of alcohol during treatment and for 3 days after the last dose",explain:"Metronidazole causes a severe disulfiram-like reaction when combined with alcohol — severe nausea, vomiting, flushing, headache, and palpitations. This is an absolute contraindication that must be emphasized strongly to every patient."},
{cat:"Immune",q:"Which class of antibiotics carries a Black Box Warning specifically for tendon rupture?",opts:["Fluoroquinolones (e.g., ciprofloxacin)","Tetracyclines (e.g., doxycycline)","Aminoglycosides (e.g., gentamicin)","Sulfonamides (e.g., Bactrim)"],correct:"Fluoroquinolones (e.g., ciprofloxacin)",explain:"Fluoroquinolones carry a Black Box Warning for tendon rupture, particularly Achilles tendon rupture. Risk is highest in patients over 60, those taking corticosteroids, and transplant recipients. Stop immediately if tendon pain develops."},
{cat:"Immune",q:"What is the standard oral dose of Acyclovir (Zovirax) for a Shingles (Herpes Zoster) outbreak?",opts:["200 mg PO 3 times daily for 10 days","400 mg PO twice daily for 7 days","800 mg PO 5 times daily for 7–10 days","1,000 mg PO once daily for 14 days"],correct:"800 mg PO 5 times daily for 7–10 days",explain:"For herpes zoster (shingles), acyclovir is dosed at 800 mg PO 5 times daily for 7–10 days. Treatment is most effective when started within 72 hours of rash onset."},
{cat:"Immune",q:"What is the primary mechanism of action of Amoxicillin?",opts:["Inhibits the 30S ribosomal subunit to block protein synthesis","Binds to penicillin-binding proteins, inhibiting bacterial cell wall synthesis and causing cell lysis","Inhibits DNA gyrase to prevent bacterial DNA replication","Blocks folic acid synthesis to slow bacterial growth"],correct:"Binds to penicillin-binding proteins, inhibiting bacterial cell wall synthesis and causing cell lysis",explain:"Amoxicillin is a beta-lactam antibiotic that binds to penicillin-binding proteins (PBPs), inhibiting cross-linking of peptidoglycan in the bacterial cell wall. This disrupts structural integrity and causes bacterial cell lysis (bactericidal)."},
{cat:"Immune",q:"What is the most dangerous adverse effect to monitor for with Clindamycin (Cleocin)?",opts:["Nephrotoxicity — kidney damage from the drug","C. difficile colitis — Clindamycin has the highest association of all antibiotics","Tendon rupture — risk with prolonged use","Red man syndrome — from rapid infusion"],correct:"C. difficile colitis — Clindamycin has the highest association of all antibiotics",explain:"Clindamycin carries a Black Box Warning because it has the HIGHEST association with C. difficile colitis of all antibiotic classes. Stop immediately if watery, bloody, or profuse diarrhea develops and test for C. diff."},
{cat:"Immune",q:"What is the mechanism of action of Acyclovir (Zovirax)?",opts:["It kills viral particles by disrupting their outer lipid envelope","It stimulates the immune system to produce antibodies against the virus","It inhibits viral DNA polymerase, stopping viral DNA replication inside infected cells","It prevents the virus from binding to host cell surface receptors"],correct:"It inhibits viral DNA polymerase, stopping viral DNA replication inside infected cells",explain:"Acyclovir is converted to its active form by viral thymidine kinase (found only in virus-infected cells), then inhibits viral DNA polymerase — stopping viral DNA replication. It does NOT cure herpes; it suppresses viral replication."},
// ── SICK CALL — NEW (pt3) ──
{cat:"CNS",q:"Which of the following is a strict contraindication for the use of Ibuprofen?",opts:["Mild to moderate fever","Pregnancy, especially in the 3rd trimester","Concurrent use of Acetaminophen","History of mild seasonal allergies"],correct:"Pregnancy, especially in the 3rd trimester",explain:"Ibuprofen is contraindicated in the 3rd trimester of pregnancy (risk of premature closure of the fetal ductus arteriosus), as well as in active GI bleeding/ulcers and severe kidney disease.",sc:1},
{cat:"CNS",q:"Aspirin irreversibly inhibits COX-1 and COX-2, providing an antiplatelet effect by stopping platelets from sticking together. How long does this specific effect last?",opts:["12 to 24 hours","3 to 5 days","For the lifespan of that platelet (7–10 days)","30 days"],correct:"For the lifespan of that platelet (7–10 days)",explain:"Because aspirin IRREVERSIBLY inhibits COX, the affected platelet cannot make new enzyme. The antiplatelet effect therefore lasts the lifespan of that platelet — about 7–10 days — until new platelets are produced.",sc:1},
{cat:"Respiratory",q:"A patient requests Pseudoephedrine for severe nasal congestion. Which condition is a strict contraindication for this oral decongestant?",opts:["Mild seasonal allergies","Severe hypertension, severe coronary artery disease, or concurrent use of MAOI antidepressants","A history of active stomach ulcers","Severe anaphylactic allergy to penicillins"],correct:"Severe hypertension, severe coronary artery disease, or concurrent use of MAOI antidepressants",explain:"Pseudoephedrine is a sympathomimetic (alpha-adrenergic agonist). It raises blood pressure and heart rate, so it is contraindicated in severe HTN, severe coronary artery disease, and with MAOIs (risk of hypertensive crisis).",sc:1},
{cat:"Respiratory",q:"Diphenhydramine (Benadryl) is a first-generation antihistamine. In which scenario is it strictly contraindicated?",opts:["A patient experiencing motion sickness","A patient with severe itching from a rash","A patient with acute asthma attacks, narrow-angle glaucoma, or urinary obstruction","A patient requiring an adjunct to epinephrine for anaphylaxis"],correct:"A patient with acute asthma attacks, narrow-angle glaucoma, or urinary obstruction",explain:"Diphenhydramine's anticholinergic effects make it contraindicated in acute asthma attacks, narrow-angle glaucoma, and urinary obstruction (it can worsen retention and raise intraocular pressure).",sc:1},
{cat:"Respiratory",q:"Guaifenesin is an expectorant for productive/congested chest coughs. For which type of cough is it generally NOT indicated unless directed by a provider?",opts:["A cough associated with a minor viral cold","Chronic coughs caused by smoking, asthma, or emphysema","A cough producing thick, adhesive mucus","A cough related to seasonal allergic rhinitis"],correct:"Chronic coughs caused by smoking, asthma, or emphysema",explain:"Guaifenesin is intended for acute productive coughs. It is not indicated for chronic coughs from smoking, asthma, or emphysema unless a provider directs it, and it requires adequate fluid intake to work.",sc:1},
{cat:"GI",q:"A patient frequently taking aluminum- or calcium-based antacids (like Tums) is at higher risk for developing which side effect?",opts:["Severe watery diarrhea","Constipation","Blackening of the tongue and stool","Increased stomach acid production"],correct:"Constipation",explain:"Aluminum- and calcium-based antacids tend to cause CONSTIPATION, while magnesium-based antacids tend to cause diarrhea. (Mnemonic: aluMINIMUM goes through you the least.)",sc:1},
{cat:"GI",q:"What specific mechanism does Omeprazole (Prilosec) use to provide strong, long-lasting acid suppression?",opts:["It binds to opiate receptors in the gut wall","It acts as a weak base that directly neutralizes hydrochloric acid","It irreversibly blocks the H+/K+ ATPase enzyme system (the “proton pump”) of the gastric parietal cell","It blocks histamine at the H2 receptors on parietal cells"],correct:"It irreversibly blocks the H+/K+ ATPase enzyme system (the “proton pump”) of the gastric parietal cell",explain:"Omeprazole is a proton pump inhibitor (PPI). It irreversibly blocks the H+/K+ ATPase pump — the final step of acid secretion — giving stronger, longer-lasting suppression than H2 blockers or antacids. Take 30–60 min before a meal.",sc:1},
{cat:"GI",q:"What is the Mechanism of Action (MOA) for the powerful antiemetic Ondansetron (Zofran)?",opts:["Selective 5-HT3 (serotonin) receptor antagonist that blocks serotonin centrally and peripherally","H2-receptor antagonist","Direct-acting alpha-adrenergic agonist","Non-selective COX inhibitor"],correct:"Selective 5-HT3 (serotonin) receptor antagonist that blocks serotonin centrally and peripherally",explain:"Ondansetron is a selective 5-HT3 (serotonin) receptor antagonist. It blocks serotonin centrally at the chemoreceptor trigger zone and peripherally at vagal nerve terminals in the GI tract to prevent nausea and vomiting.",sc:1},
{cat:"GI",q:"Which condition is a strict contraindication for administering Ondansetron (Zofran)?",opts:["Mild dehydration","Severe renal disease","Known long QT syndrome","First trimester of pregnancy"],correct:"Known long QT syndrome",explain:"Ondansetron can prolong the QT interval, so it is contraindicated in patients with known long QT syndrome (risk of life-threatening arrhythmia such as torsades de pointes).",sc:1},
// ── PHARMACOLOGY BASICS ──
{cat:"Basics",q:"Which statement BEST describes pharmacokinetics?",opts:["The study of how drugs bind to receptors and produce effects","The study of how drugs are moved throughout the body — absorption, distribution, metabolism, and excretion","The study of how drugs are chemically synthesized in the laboratory","The study of the relationship between drug concentration and clinical effect"],correct:"The study of how drugs are moved throughout the body — absorption, distribution, metabolism, and excretion",explain:"Pharmacokinetics is the study of how the body handles a drug — ADME: Absorption (how the drug gets into the bloodstream), Distribution (how it travels to the target site), Metabolism (how it is broken down), and Excretion (how it leaves the body)."},
{cat:"Basics",q:"What is the most common site of drug metabolism in the body?",opts:["Kidneys","Small intestine","Liver","Lungs"],correct:"Liver",explain:"The liver is the primary site of drug metabolism. It contains cytochrome P450 (CYP450) enzymes that break down most drugs. Liver disease significantly affects drug metabolism and toxicity risk."},
{cat:"Basics",q:"What is the BEST way to avoid the first-pass effect?",opts:["Taking the drug on an empty stomach","Administering the medication via a parenteral route (SubQ, IM, or IV)","Taking the drug with a full glass of water","Crushing the tablet before swallowing"],correct:"Administering the medication via a parenteral route (SubQ, IM, or IV)",explain:"The first-pass effect occurs when drugs taken orally are metabolized by the liver before reaching systemic circulation. Parenteral routes (IV, IM, SubQ) bypass the GI tract and liver entirely, achieving higher bioavailability."},
{cat:"Basics",q:"What is the definition of a drug's half-life?",opts:["The time it takes for a drug to reach peak concentration in the bloodstream","The time it takes for the drug concentration in the body to be reduced by half (50%)","The time between doses of a medication","The time it takes for a drug to be completely eliminated from the body"],correct:"The time it takes for the drug concentration in the body to be reduced by half (50%)",explain:"A drug's half-life is the time required for the concentration of the drug in the body to decrease by 50%. It determines dosing intervals — short half-life drugs need more frequent dosing; long half-life drugs need less frequent dosing."},
{cat:"Basics",q:"Which of the following is an example of a Schedule II controlled substance?",opts:["Cough syrup with codeine (Schedule V)","Tramadol (Schedule IV)","Oxycodone — high abuse potential, no refills allowed","Testosterone — moderate abuse potential (Schedule III)"],correct:"Oxycodone — high abuse potential, no refills allowed",explain:"Oxycodone is a Schedule II controlled substance — high abuse potential with currently accepted medical use. Schedule II drugs require a written prescription and cannot be refilled (a new prescription is needed each time)."},
// ── RESPIRATORY ──
{cat:"Respiratory",q:"Which inhaler is considered the RESCUE inhaler for an acute asthma attack?",opts:["Salmeterol (Serevent) — long-acting beta-2 agonist","Tiotropium (Spiriva) — anticholinergic bronchodilator","Albuterol (Ventolin) — short-acting beta-2 agonist","Fluticasone (Flovent) — inhaled corticosteroid"],correct:"Albuterol (Ventolin) — short-acting beta-2 agonist",explain:"Albuterol (Ventolin, Proventil) is the rescue inhaler. It is a short-acting beta-2 agonist (SABA) that works within minutes to bronchodilate. SABAs are for ACUTE relief only — NOT maintenance therapy."},
{cat:"Respiratory",q:"What important patient education is needed for BOTH inhaled corticosteroids AND short-acting beta-2 agonists?",opts:["Rinse the mouth with water after administration to prevent oral thrush","Take on an empty stomach to improve absorption","Store at room temperature away from sunlight","Never use a spacer device — it reduces drug delivery"],correct:"Rinse the mouth with water after administration to prevent oral thrush",explain:"Rinsing the mouth after inhaled corticosteroids (ICS) is critical to prevent oral thrush (Candida infection). This is also recommended after beta-2 agonists. The deposited drug in the mouth can cause fungal overgrowth."},
{cat:"Respiratory",q:"Acetylcysteine (Mucomyst) has a strict contraindication in patients with which condition?",opts:["Hypertension","Diabetes mellitus","Asthma — may worsen bronchospasm","Renal failure"],correct:"Asthma — may worsen bronchospasm",explain:"Acetylcysteine can trigger or worsen bronchospasm in patients with asthma. Always assess for asthma history before administering. If used in asthmatic patients, a bronchodilator must be given first."},
{cat:"Respiratory",q:"Which sign would indicate life-threatening toxicity in a patient on Theophylline?",opts:["Mild headache and fatigue","Life-threatening cardiac arrhythmias and seizures","Mild nausea and decreased appetite","Increased drowsiness"],correct:"Life-threatening cardiac arrhythmias and seizures",explain:"Theophylline has a narrow therapeutic index (10–20 mcg/mL). Levels above 20 mcg/mL are toxic and can cause life-threatening cardiac arrhythmias and seizures. Levels must be monitored closely."},
{cat:"Respiratory",q:"What dietary modification is MOST important for a patient taking Theophylline?",opts:["Avoid all dairy products","Avoid caffeine — coffee, cola, chocolate — as it potentiates theophylline toxicity","Increase vitamin C intake","Avoid all spicy foods"],correct:"Avoid caffeine — coffee, cola, chocolate — as it potentiates theophylline toxicity",explain:"Caffeine and theophylline are both methylxanthines. Caffeine increases theophylline levels and toxicity risk. Patients must avoid all caffeine-containing foods and beverages while taking theophylline."},
// ── CNS ──
{cat:"CNS",q:"What is the mechanism of action of Triptans (e.g., sumatriptan) in treating migraines?",opts:["They increase serotonin production in the brain to improve mood and reduce pain","They cause constriction of dilated cranial arteries and decrease vasoactive neuropeptide release","They block pain signals by binding to opioid receptors in the CNS","They reduce inflammation of the meninges surrounding the brain"],correct:"They cause constriction of dilated cranial arteries and decrease vasoactive neuropeptide release",explain:"Triptans activate serotonin 5-HT1B/1D receptors → vasoconstriction of cranial blood vessels → reversal of the vasodilation that causes migraine pain. They also inhibit the release of vasoactive neuropeptides that perpetuate the migraine."},
{cat:"CNS",q:"Which is a dangerous and potentially life-threatening adverse reaction of SSRIs?",opts:["Dry mouth and constipation from anticholinergic effects","Serotonin syndrome — from excess serotonin in the nervous system","Rebound depression that is worse than the original","Agranulocytosis — loss of white blood cells"],correct:"Serotonin syndrome — from excess serotonin in the nervous system",explain:"Serotonin syndrome occurs when there is excess serotonergic activity in the nervous system — often from combining SSRIs with other serotonergic drugs or MAOIs. Signs: agitation, tremor, hyperthermia, muscle rigidity, diaphoresis, tachycardia."},
{cat:"CNS",q:"What is the most important patient education regarding orthostatic hypotension for patients taking TCAs?",opts:["Take the medication with food to prevent dizziness","Change positions slowly — sit up before standing — to prevent falls from orthostatic hypotension","Drink extra fluids to maintain blood pressure","Avoid all physical activity while taking this medication"],correct:"Change positions slowly — sit up before standing — to prevent falls from orthostatic hypotension",explain:"TCAs block alpha-1 receptors, causing peripheral vasodilation and orthostatic hypotension. Patients must change positions SLOWLY (lie → sit → stand) and dangle their legs at the bedside before standing to prevent falls."},
{cat:"CNS",q:"Why are NSAIDs contraindicated in patients with asthma who are sensitive to aspirin?",opts:["NSAIDs reduce oxygen delivery to the lungs","NSAIDs can trigger bronchospasms in aspirin-sensitive asthmatic patients","NSAIDs reduce the effectiveness of bronchodilators","NSAIDs cause excess mucus production in the airways"],correct:"NSAIDs can trigger bronchospasms in aspirin-sensitive asthmatic patients",explain:"Aspirin-sensitive asthma (Samter's Triad) occurs in ~10% of asthmatics. COX inhibition shifts arachidonic acid metabolism toward leukotriene production → severe bronchospasm. All NSAIDs are contraindicated in these patients."},
{cat:"CNS",q:"What is the antidote for Acetaminophen (Tylenol) overdose?",opts:["Naloxone (Narcan) — reverses the toxic effects","Vitamin K — restores normal liver clotting factors","Acetylcysteine (Acetadote) — replenishes glutathione in the liver","Flumazenil — reverses the CNS effects"],correct:"Acetylcysteine (Acetadote) — replenishes glutathione in the liver",explain:"N-acetylcysteine (Acetylcysteine/Acetadote) is the specific antidote for acetaminophen overdose. It replenishes glutathione, which is depleted by the toxic metabolite NAPQI. Must be given within 8–10 hours of overdose for best results."},
// ── CARDIOVASCULAR ──
{cat:"Cardiovascular",q:"Which is a dangerous and potentially life-threatening side effect of ACE inhibitors?",opts:["Persistent dry cough requiring medication change","Angioedema — rapid swelling of the face, lips, and neck that can obstruct the airway","Mild hyperkalemia requiring dietary adjustment","Peripheral edema in the lower extremities"],correct:"Angioedema — rapid swelling of the face, lips, and neck that can obstruct the airway",explain:"Angioedema is a rare but life-threatening side effect of ACE inhibitors. It occurs due to bradykinin accumulation. Symptoms include sudden swelling of the face, lips, tongue, and throat. STOP the drug immediately and manage the airway."},
{cat:"Cardiovascular",q:"What dietary modification is MOST important for patients taking Calcium Channel Blockers (CCBs)?",opts:["Avoid all dairy products — decreases absorption","Avoid drinking grapefruit juice — significantly increases drug levels","Increase potassium-rich foods — prevents drug toxicity","Avoid all high-fat foods — decreases GI absorption"],correct:"Avoid drinking grapefruit juice — significantly increases drug levels",explain:"Grapefruit juice inhibits the CYP3A4 enzyme that metabolizes CCBs. This causes significantly elevated drug levels → increased hypotension, bradycardia, and toxicity risk. Patients must avoid grapefruit juice entirely."},
{cat:"Cardiovascular",q:"Which vital sign is most significantly lowered by Beta-Adrenergic Blockers?",opts:["Respiratory rate","Heart rate","Body temperature","Oxygen saturation"],correct:"Heart rate",explain:"Beta-blockers (-OLOL suffix) primarily decrease heart rate by blocking beta-1 receptors in the heart. Hold if HR < 60 bpm. They also decrease blood pressure and contractility. They MASK tachycardia as a sign of hypoglycemia in diabetic patients."},
{cat:"Cardiovascular",q:"What is the most important patient education to prevent rebound hypertension?",opts:["Take the medication at the exact same time every day","Never stop blood pressure medications abruptly — they must be gradually tapered","Take the medication with food to improve absorption","Double the dose if one dose is missed to maintain levels"],correct:"Never stop blood pressure medications abruptly — they must be gradually tapered",explain:"Abrupt discontinuation of antihypertensives (especially beta-blockers and clonidine) causes a dangerous rebound surge in blood pressure — potentially causing MI, stroke, or hypertensive emergency. Always taper."},
{cat:"Cardiovascular",q:"What is a known side effect of Alpha-2 Adrenergic Agonists (e.g., clonidine)?",opts:["Dry cough and angioedema","Dry mouth and drowsiness from central CNS suppression","Severe peripheral edema and weight gain","Tachycardia and hypertension"],correct:"Dry mouth and drowsiness from central CNS suppression",explain:"Alpha-2 agonists like clonidine work centrally in the brain to reduce sympathetic outflow. The most common side effects are dry mouth and drowsiness. They also cause orthostatic hypotension. Rebound HTN occurs if stopped abruptly."},
// ── IMMUNE SYSTEM ──
{cat:"Immune",q:"What is the PURPOSE of obtaining a Culture and Sensitivity test before starting antibiotics?",opts:["To determine the correct dose based on the patient's weight","To identify what type of organism is causing the infection and which antibiotic will effectively treat it","To check for kidney function before dosing","To confirm the patient has no drug allergies"],correct:"To identify what type of organism is causing the infection and which antibiotic will effectively treat it",explain:"The Culture identifies WHICH organism is causing the infection. The Sensitivity test identifies WHICH antibiotics are effective against it. This guides appropriate antibiotic selection and prevents unnecessary broad-spectrum antibiotic use."},
{cat:"Immune",q:"What dangerous side effect occurs when Vancomycin is infused too rapidly?",opts:["Anaphylaxis — true allergic reaction requiring epinephrine","Red man syndrome — flushing and itching of the face and body from histamine release (rate-related, not allergy)","Severe bronchospasm and respiratory distress","Acute renal failure from rapid drug exposure"],correct:"Red man syndrome — flushing and itching of the face and body from histamine release (rate-related, not allergy)",explain:"Red man syndrome is NOT a true allergy — it is a rate-dependent reaction caused by non-immunologic histamine release. It causes flushing, redness, and itching of the face, neck, and upper body. Prevention: infuse over at LEAST 60 minutes."},
{cat:"Immune",q:"What allergy must ALWAYS be assessed before administering any Cephalosporin antibiotic?",opts:["Sulfa allergy — cross-reactivity with sulfonamides","Penicillin allergy — approximately 1–2% cross-reactivity","Aspirin allergy — cross-reactivity with NSAIDs","Aminoglycoside allergy — similar class nephrotoxicity"],correct:"Penicillin allergy — approximately 1–2% cross-reactivity",explain:"Cephalosporins and penicillins are both beta-lactam antibiotics and share a ~1–2% cross-reactivity. Always ask about penicillin allergy before giving any cephalosporin. With history of anaphylaxis to PCN, avoid cephalosporins entirely."},
{cat:"Immune",q:"Which antibiotic class carries a Black Box Warning for tendon rupture risk?",opts:["Aminoglycosides — nephrotoxicity and ototoxicity risk","Tetracyclines — tooth discoloration risk","Fluoroquinolones (e.g., ciprofloxacin, levofloxacin)","Cephalosporins — Stevens-Johnson syndrome risk"],correct:"Fluoroquinolones (e.g., ciprofloxacin, levofloxacin)",explain:"Fluoroquinolones carry a Black Box Warning for tendon rupture (especially Achilles tendon) and peripheral neuropathy. Risk increases in patients over 60, those on corticosteroids, and organ transplant recipients."},
{cat:"Immune",q:"What is the key difference between bacteriostatic and bactericidal antibiotics?",opts:["Bacteriostatic drugs are more expensive; bactericidal drugs are cheaper","Bacteriostatic slows or prevents bacterial growth; bactericidal directly kills the bacteria","Bacteriostatic drugs treat gram-positive bacteria; bactericidal treats gram-negative bacteria","Bacteriostatic requires IV administration; bactericidal can be given orally"],correct:"Bacteriostatic slows or prevents bacterial growth; bactericidal directly kills the bacteria",explain:"Bacteriostatic antibiotics slow or prevent bacterial GROWTH — they rely on the patient's immune system to eliminate the bacteria. Bactericidal antibiotics directly KILL bacteria. Bactericidal agents are preferred in immunocompromised patients."},
{cat:"Immune",q:"What are the two most serious adverse effects that must be monitored with Aminoglycosides?",opts:["Hepatotoxicity and pulmonary toxicity","Nephrotoxicity (kidney damage) and ototoxicity (permanent hearing loss)","Cardiotoxicity and peripheral neuropathy","GI bleeding and peptic ulcer disease"],correct:"Nephrotoxicity (kidney damage) and ototoxicity (permanent hearing loss)",explain:"Aminoglycosides are nephrotoxic and ototoxic. Nephrotoxicity: monitor BUN and creatinine. Ototoxicity: monitor for tinnitus and hearing changes. Both toxicities can be IRREVERSIBLE if the drug is not stopped promptly."},
{cat:"Immune",q:"What critical patient education should be given for ANY antibiotic course?",opts:["Stop the antibiotic as soon as you feel better to avoid side effects","Take the medication only when symptoms are at their worst","Finish the entire course of antibiotic therapy even if symptoms resolve completely","Double the dose if a dose is missed to maintain therapeutic levels"],correct:"Finish the entire course of antibiotic therapy even if symptoms resolve completely",explain:"Stopping antibiotics early is one of the leading causes of antibiotic resistance. Even after symptoms resolve, bacteria may still be present. Incomplete courses allow resistant strains to survive and proliferate."},
// ── GI (additional) ──
{cat:"GI",q:"What is the mechanism of action of Antacids?",opts:["They inhibit the proton pump from producing acid","They block H2 receptors on gastric parietal cells","They neutralize hydrochloric acid already produced in the stomach quickly","They coat the stomach lining to prevent irritation"],correct:"They neutralize hydrochloric acid already produced in the stomach quickly",explain:"Antacids are basic (alkaline) compounds that directly neutralize hydrochloric acid in the stomach — raising gastric pH rapidly. They act quickly but only for a short duration. Examples: calcium carbonate (Tums), magnesium hydroxide (Maalox)."},
{cat:"GI",q:"Why are Antacids that contain salicylates contraindicated in children with viral illnesses?",opts:["They cause severe nephrotoxicity in children","They can lead to Reye's syndrome — a rare but life-threatening condition affecting the brain and liver","They cause tooth enamel erosion in children","They interfere with vaccine immunity in children"],correct:"They can lead to Reye's syndrome — a rare but life-threatening condition affecting the brain and liver",explain:"Products like Pepto-Bismol contain bismuth subsalicylate — a salicylate compound similar to aspirin. Salicylates given to children with viral illnesses can cause Reye's syndrome, causing life-threatening brain swelling and liver failure."},
{cat:"GI",q:"What is the mechanism of action of Docusate Sodium (Colace)?",opts:["It stimulates intestinal smooth muscle contractions to move stool faster","It draws water into the colon through osmosis","It allows water and fat to enter the stool, making it softer and easier to pass","It neutralizes stomach acid to reduce straining from reflux"],correct:"It allows water and fat to enter the stool, making it softer and easier to pass",explain:"Docusate sodium is a surfactant — it lowers the surface tension of stool, allowing water and lipids to penetrate it. This softens the stool without stimulating bowel contractions. It does NOT cause urgency or dependence."},
{cat:"GI",q:"What is the most severe adverse reaction of long-term Metoclopramide (Reglan) use?",opts:["Stevens-Johnson Syndrome — severe skin reaction","Serotonin syndrome — from excess serotonin stimulation","Tardive dyskinesia — irreversible involuntary movements of the tongue and face (BLACK BOX WARNING)","Nephrotoxicity — progressive kidney failure"],correct:"Tardive dyskinesia — irreversible involuntary movements of the tongue and face (BLACK BOX WARNING)",explain:"Tardive dyskinesia (TD) is an irreversible movement disorder characterized by involuntary repetitive movements of the face, tongue, and extremities. It carries a BLACK BOX WARNING for Metoclopramide. Avoid use beyond 12 weeks."},
{cat:"GI",q:"What is the mechanism of action of Ondansetron (Zofran)?",opts:["Stimulates gastric motility to prevent reflux of stomach contents","Inhibits and prevents movement of serotonin, calming the chemoreceptor trigger zone in the brain","Blocks dopamine receptors in the GI tract and brain to reduce nausea","Coats the stomach lining to prevent acid irritation that triggers nausea"],correct:"Inhibits and prevents movement of serotonin, calming the chemoreceptor trigger zone in the brain",explain:"Ondansetron blocks 5-HT3 serotonin receptors in both the GI tract AND the chemoreceptor trigger zone (CTZ) in the brain. The CTZ is responsible for triggering the vomiting reflex — blocking it prevents nausea and vomiting."},
{cat:"GI",q:"Why is Misoprostol (Cytotec) absolutely contraindicated in pregnancy?",opts:["It significantly increases the risk of pre-term labor contractions","It causes severe hepatotoxicity in the developing fetus","It can cause a miscarriage by causing powerful uterine contractions","It blocks critical fetal hormone development"],correct:"It can cause a miscarriage by causing powerful uterine contractions",explain:"Misoprostol is a Pregnancy Category X drug — its prostaglandin activity stimulates powerful uterine contractions, which can cause miscarriage or premature labor. A pregnancy test must be done before prescribing for GI indications."},
// ── CARDIOVASCULAR (additional) ──
{cat:"Cardiovascular",q:"What is the definition of orthostatic hypotension?",opts:["High blood pressure that occurs during physical exercise","Low blood pressure that occurs due to a position change from lying or sitting to standing","Normal blood pressure variation throughout the day","Blood pressure that drops suddenly when sitting down"],correct:"Low blood pressure that occurs due to a position change from lying or sitting to standing",explain:"Orthostatic hypotension is defined as a drop of ≥20 mmHg systolic or ≥10 mmHg diastolic when transitioning from lying to sitting or from sitting to standing. It causes dizziness and fall risk."},
{cat:"Cardiovascular",q:"The medication suffix '-pril' identifies which class of antihypertensives?",opts:["Angiotensin Receptor Blockers (ARBs)","Beta-Adrenergic Blockers (beta blockers)","ACE Inhibitors","Calcium Channel Blockers"],correct:"ACE Inhibitors",explain:"The -PRIL suffix identifies ACE inhibitors (e.g., lisinoPRIL, enalaPRIL, captoPRIL). They inhibit angiotensin-converting enzyme → prevent conversion of angiotensin I to II → reduce vasoconstriction and aldosterone release."},
{cat:"Cardiovascular",q:"The medication suffix '-dipine' identifies which class of antihypertensives?",opts:["ACE Inhibitors","Calcium Channel Blockers","Angiotensin Receptor Blockers (ARBs)","Beta-Adrenergic Blockers"],correct:"Calcium Channel Blockers",explain:"The -DIPINE suffix identifies Calcium Channel Blockers (e.g., amloDIPINE, nifeDIPINE). They block calcium entry into smooth muscle cells → vasodilation → decreased blood pressure."},
{cat:"Cardiovascular",q:"What is the mechanism of action of Proton Pump Inhibitors (PPIs)?",opts:["They neutralize acid in the stomach immediately after ingestion","They block H2 receptors to slow acid secretion","They inhibit the proton pump in stomach parietal cells, blocking the final step of acid production","They coat the stomach lining to prevent acid damage"],correct:"They inhibit the proton pump in stomach parietal cells, blocking the final step of acid production",explain:"PPIs irreversibly inhibit the H+/K+ ATPase (proton pump) enzyme on gastric parietal cells — this blocks the FINAL and most potent step of acid production. They are the most effective acid suppressors available."},
// ── RESPIRATORY (additional) ──
{cat:"Respiratory",q:"What is the primary therapeutic use for Triptans (sumatriptan, rizatriptan)?",opts:["Prevention of migraines taken daily as a maintenance drug","Treatment of acute migraine pain and cluster headaches — taken at first sign of attack","Management of generalized anxiety and stress headaches","Long-term treatment of chronic daily headache disorder"],correct:"Treatment of acute migraine pain and cluster headaches — taken at first sign of attack",explain:"Triptans are for ACUTE treatment of migraine and cluster headaches, NOT prevention. They must be taken at the very FIRST sign of a migraine for maximum effectiveness. They are NOT rescue medications for all headaches."},
{cat:"Respiratory",q:"What is the most important patient education when prescribing a Triptan?",opts:["Take it daily to prevent future migraines","Do not take it on an empty stomach — always eat a meal first","Take the first dose as soon as you have any sign of a migraine for maximum effectiveness","Take it only when the migraine has reached its peak severity"],correct:"Take the first dose as soon as you have any sign of a migraine for maximum effectiveness",explain:"Triptans are most effective when taken at the EARLIEST sign of a migraine — aura, visual changes, or the very onset of headache. Waiting until the headache is severe significantly reduces their effectiveness."},
// ── CNS (additional) ──
{cat:"CNS",q:"What is the most serious adverse reaction of Opioids that must be monitored at all times?",opts:["Severe constipation requiring hospitalization","Respiratory depression — can cause life-threatening apnea","Extreme sedation requiring protective restraints","Severe hypertension leading to stroke"],correct:"Respiratory depression — can cause life-threatening apnea",explain:"Respiratory depression is the most dangerous opioid side effect. A respiratory rate below 12 breaths/min requires immediate intervention. Have Naloxone (Narcan) readily available when administering opioids."},
{cat:"CNS",q:"Which vital signs should be closely monitored when a patient is receiving opioid analgesics?",opts:["Temperature and urine output only","Heart rate, blood pressure, and respiratory rate","Oxygen saturation and hemoglobin only","Blood glucose and electrolytes"],correct:"Heart rate, blood pressure, and respiratory rate",explain:"When administering opioids, monitor HR, BP, and especially respiratory rate. Hold opioids if RR < 12 breaths/min. Also monitor level of consciousness. Opioids cause hypotension, bradycardia, and respiratory depression."},
{cat:"CNS",q:"What is the antidote for opioid overdose?",opts:["Flumazenil (Romazicon) — reverses benzodiazepine effects","Naloxone (Narcan) — reverses opioid receptor effects","Acetylcysteine (Acetadote) — replenishes hepatic glutathione","Atropine — reverses cholinergic crisis"],correct:"Naloxone (Narcan) — reverses opioid receptor effects",explain:"Naloxone (Narcan) is a competitive opioid antagonist that rapidly reverses opioid-induced respiratory depression, sedation, and analgesia. It competes with opioids at mu receptors. Can be given IM, IV, or intranasally."},
{cat:"CNS",q:"What patient education should be given to prevent opioid-induced constipation?",opts:["Decrease fluid intake — fluids dilute the opioid effect","Take a stimulant laxative only if constipation is severe","Increase intake of fruits, fiber, and fluids — start a bowel regimen from day 1","Take an antidiarrheal medication prophylactically"],correct:"Increase intake of fruits, fiber, and fluids — start a bowel regimen from day 1",explain:"Opioid-induced constipation is the MOST COMMON side effect and is experienced by nearly all patients on opioids. It does NOT improve with time (unlike other side effects). Patients need a scheduled bowel regimen with fiber, fluids, and stool softeners from day 1."},
{cat:"Immune",q:"What is the difference between bacteriostatic and bactericidal antibiotics?",opts:["Bacteriostatic kills bacteria; bactericidal slows their growth","Bacteriostatic drugs require IV administration; bactericidal can be given orally","Bacteriostatic slows or prevents bacterial growth; bactericidal directly kills the bacteria","Bacteriostatic is more potent than bactericidal for severe infections"],correct:"Bacteriostatic slows or prevents bacterial growth; bactericidal directly kills the bacteria",explain:"Bacteriostatic = STOPS bacterial growth (relies on immune system to finish). Bactericidal = KILLS bacteria directly. Examples: Bacteriostatic: tetracyclines, sulfonamides, clindamycin. Bactericidal: penicillins, cephalosporins, fluoroquinolones, aminoglycosides."},
{cat:"Immune",q:"Why are Tetracyclines contraindicated in children under 8 and in pregnant women?",opts:["They cross the placenta and cause cardiac birth defects","They cause permanent tooth discoloration and impair bone mineralization in developing tissues","They cause severe hepatic failure in young children","They destroy the fetal immune system"],correct:"They cause permanent tooth discoloration and impair bone mineralization in developing tissues",explain:"Tetracyclines bind to calcium in calcifying tissues — causing permanent yellow-gray tooth discoloration and inhibiting bone growth in children under 8. They cross the placenta and affect fetal teeth and bones as well."},
// ── SICK CALL · SELECT ALL THAT APPLY (multi-select) ──
{type:"multi",cat:"Physical Exam",sc:1,q:"Ottawa Ankle Rules — select ALL criteria that require an X-ray for an ankle injury:",options:["Bone tenderness at posterior edge or tip of lateral malleolus (distal 6 cm)","Bone tenderness at posterior edge or tip of medial malleolus (distal 6 cm)","Inability to bear weight (4 steps) immediately after injury and in clinic","Visible swelling of the ankle","Pain with inversion stress test"],correct:["Bone tenderness at posterior edge or tip of lateral malleolus (distal 6 cm)","Bone tenderness at posterior edge or tip of medial malleolus (distal 6 cm)","Inability to bear weight (4 steps) immediately after injury and in clinic"],explain:"X-ray is indicated with malleolar-zone pain PLUS bony tenderness at either malleolus or inability to bear weight. Swelling and a positive inversion stress test are NOT part of the Ottawa Ankle Rules."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Ottawa Foot Rules — select ALL criteria requiring an X-ray for midfoot pain:",options:["Bone tenderness at base of 5th metatarsal","Bone tenderness at navicular bone","Inability to bear weight (4 steps) immediately after injury and in clinic","Pain along the foot arch","Swelling on dorsum of foot"],correct:["Bone tenderness at base of 5th metatarsal","Bone tenderness at navicular bone","Inability to bear weight (4 steps) immediately after injury and in clinic"],explain:"X-ray is indicated with midfoot-zone pain PLUS tenderness at the base of the 5th metatarsal or the navicular, or inability to bear weight. Arch pain and dorsal swelling do not meet criteria."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Ottawa Knee Rules — select ALL criteria requiring an X-ray for a knee injury:",options:["Age 55 or older","Isolated tenderness of the patella","Tenderness at head of fibula","Inability to flex to 90 degrees","Inability to bear weight (4 steps)","Knee effusion/swelling","Positive McMurray's test"],correct:["Age 55 or older","Isolated tenderness of the patella","Tenderness at head of fibula","Inability to flex to 90 degrees","Inability to bear weight (4 steps)"],explain:"Five criteria require imaging: age 55+, isolated patellar tenderness, fibular head tenderness, inability to flex to 90°, or inability to bear weight. Effusion and a positive McMurray's test alone do not."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL neurological red flags for hypertensive emergency:",options:["Severe headache","Altered mental status","Dizziness","Weakness","Mild headache","Tremor"],correct:["Severe headache","Altered mental status","Dizziness","Weakness"],explain:"Neurological red flags signaling end-organ damage are severe headache, altered mental status, dizziness, and weakness. A mild headache or tremor are not emergency red flags."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL cardiopulmonary signs of hypertensive emergency:",options:["Dyspnea","Chest pain","Palpitations","Mild tachycardia (HR 100-110)","Cough"],correct:["Dyspnea","Chest pain","Palpitations"],explain:"Cardiopulmonary red flags are dyspnea, chest pain, and palpitations. Mild tachycardia and an isolated cough are not emergency indicators."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL additional signs indicating hypertensive emergency:",options:["Blurry vision","Severe epistaxis","Hematuria","Mild epistaxis (few droplets)","Fatigue"],correct:["Blurry vision","Severe epistaxis","Hematuria"],explain:"Other end-organ red flags include blurry vision, severe epistaxis, and hematuria. A few droplets of epistaxis or generalized fatigue do not signal an emergency."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL Cauda Equina red flags requiring emergency referral:",options:["Saddle anesthesia","Fecal incontinence","Urinary incontinence","Severe bilateral leg weakness","Unilateral leg weakness","Acute lower back pain with activity"],correct:["Saddle anesthesia","Fecal incontinence","Urinary incontinence","Severe bilateral leg weakness"],explain:"Cauda equina red flags are saddle anesthesia, fecal incontinence, urinary incontinence, and severe bilateral leg weakness. Unilateral weakness or activity-related back pain are less specific."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL systemic red flags in back pain requiring further workup:",options:["History of cancer","Unexplained weight loss","Fever","Night pain","Pain worse with exercise","Recent heavy lifting episode"],correct:["History of cancer","Unexplained weight loss","Fever","Night pain"],explain:"Systemic red flags suggesting serious pathology are history of cancer, unexplained weight loss, fever, and night pain. Pain worse with exercise or recent heavy lifting points to mechanical back pain."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL findings associated with appendicitis:",options:["McBurney's Point tenderness","Rovsing's sign","Right lower quadrant pain","Epigastric pain","Left upper quadrant rebound"],correct:["McBurney's Point tenderness","Rovsing's sign","Right lower quadrant pain"],explain:"Appendicitis classically presents with McBurney's point tenderness, a positive Rovsing's sign, and right lower quadrant pain. Epigastric pain and LUQ rebound are not characteristic localizing signs."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL signs suggestive of cholecystitis:",options:["Murphy's sign positive","Right upper quadrant pain/tenderness","Fever","Left-sided abdominal pain","Diarrhea"],correct:["Murphy's sign positive","Right upper quadrant pain/tenderness","Fever"],explain:"Cholecystitis presents with a positive Murphy's sign, right upper quadrant pain/tenderness, and fever. Left-sided pain and diarrhea are not typical findings."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL findings indicating peritonitis:",options:["Rebound tenderness","Abdominal rigidity","Severe acute abdominal pain","Localized point tenderness only","Mild diffuse discomfort"],correct:["Rebound tenderness","Abdominal rigidity","Severe acute abdominal pain"],explain:"Peritonitis is marked by rebound tenderness, abdominal rigidity, and severe acute pain. Localized point tenderness only or mild diffuse discomfort argue against peritonitis."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Modified Centor Score — select ALL criteria that add 1 point each (4 total possible):",options:["Absence of cough","Swollen, tender anterior cervical nodes","Temperature > 100.4°F (38°C)","Tonsillar exudate or swelling","Presence of cough","Posterior cervical node enlargement"],correct:["Absence of cough","Swollen, tender anterior cervical nodes","Temperature > 100.4°F (38°C)","Tonsillar exudate or swelling"],explain:"Each adds 1 point: absence of cough, swollen/tender anterior cervical nodes, temp > 100.4°F, and tonsillar exudate/swelling. Presence of cough and posterior cervical nodes are not Centor criteria."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL conditions associated with anterior cervical lymphadenopathy:",options:["Strep pharyngitis","Viral upper respiratory infection (URI)","Oral/dental infections","Mononucleosis (EBV)","Scalp infections"],correct:["Strep pharyngitis","Viral upper respiratory infection (URI)","Oral/dental infections"],explain:"Anterior cervical nodes are associated with strep pharyngitis, viral URIs, and oral/dental infections. Mononucleosis (EBV) drains to POSTERIOR cervical nodes; scalp infections do not localize here."},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL correct lymph node–infection associations:",options:["Posterior cervical nodes → Epstein-Barr Virus (Mono)","Submandibular nodes → Oral/dental infections","Submandibular nodes → Strep pharyngitis","Submental nodes → Lower lip, floor-of-mouth, dental infections","Anterior cervical nodes → Scalp infections","Submental nodes → Pharyngeal infections only"],correct:["Posterior cervical nodes → Epstein-Barr Virus (Mono)","Submandibular nodes → Oral/dental infections","Submandibular nodes → Strep pharyngitis","Submental nodes → Lower lip, floor-of-mouth, dental infections"],explain:"Correct pairings: posterior cervical → EBV/Mono; submandibular → oral/dental and Strep; submental → lower lip, floor-of-mouth, dental. Anterior cervical nodes are not for scalp infections, and submental nodes are not 'pharyngeal only.'"},
{type:"multi",cat:"Physical Exam",sc:1,q:"Select ALL four lymph nodes typically checked in a patient with cold and flu symptoms:",options:["Anterior Cervical","Posterior Cervical","Submandibular","Submental","Axillary","Inguinal"],correct:["Anterior Cervical","Posterior Cervical","Submandibular","Submental"],explain:"The four HEENT nodes checked for cold/flu are anterior cervical, posterior cervical, submandibular, and submental. Axillary and inguinal nodes are not part of this routine check."}
];

